var e={},t=JSON.parse(`{"e100":{"name":"Curcumine","note":"Natuurlijke geelwortelkleurstof.","detail":{"risks":"Het gele pigment uit kurkumawortel, dat al millennia in de keuken wordt gebruikt. Het wordt slecht door het lichaam opgenomen en grotendeels onveranderd uitgescheiden.","benefits":"","interestingFact":"","research":""}},"e101":{"name":"Riboflavine","note":"Vitamine B2 gebruikt als kleurstof.","detail":{"risks":"Een vitamine die een dubbelrol vervult als gele kleurstof — dezelfde riboflavine die je lichaam gebruikt om voedsel om te zetten in energie.","benefits":"","interestingFact":"","research":""}},"e102":{"name":"Tartrazine","note":"Azo-kleurstof in verband gebracht met hyperactiviteit bij kinderen; EU-waarschuwingsetiket verplicht.","detail":{"risks":"Een synthetische azo-kleurstof. Een van de \\"Southampton six\\"-kleurstoffen die de studie in Lancet 2007 linkte aan toegenomen hyperactiviteit bij kinderen — EU-producten die het bevatten moeten een waarschuwingsetiket dragen.","benefits":"","interestingFact":"","research":""}},"e104":{"name":"Kinolinegeel","note":"Synthetische kleurstof in verband gebracht met hyperactiviteit; EU-waarschuwingsetiket verplicht.","detail":{"risks":"Een synthetische gele kleurstof die in de EU werd beperkt na de bevindingen uit Southampton; verboden in voeding in de VS, Canada en Japan.","benefits":"","interestingFact":"","research":""}},"e110":{"name":"Zonnegeel FCF","note":"Azo-kleurstof in verband gebracht met hyperactiviteit bij kinderen; EU-waarschuwingsetiket verplicht.","detail":{"risks":"Een uit aardolie verkregen azo-kleurstof uit de \\"Southampton six\\". EFSA heeft de aanvaardbare dagelijkse inname in 2009 drastisch verlaagd, voordat deze na nieuwe gegevens gedeeltelijk werd versoepeld.","benefits":"","interestingFact":"","research":""}},"e120":{"name":"Cochenille (karmijn)","note":"Kleurstof van insecten; kan allergische reacties veroorzaken.","detail":{"risks":"Een dieprode kleurstof geëxtraheerd uit gedroogde cochenille-insecten — er gaan ongeveer 70.000 insecten in 500 g kleurstof. Natuurlijk, maar een van de weinige kleurstoffen met gedocumenteerde (soms ernstige) allergische reacties.","benefits":"","interestingFact":"","research":""}},"e122":{"name":"Azorubine","note":"Azo-kleurstof in verband gebracht met hyperactiviteit; EU-waarschuwingsetiket verplicht.","detail":{"risks":"Een synthetische azo-kleurstof die verboden is in de VS en diverse andere landen; EU-producten vereisen een waarschuwingsetiket voor hyperactiviteit.","benefits":"","interestingFact":"","research":""}},"e124":{"name":"Ponceau 4R","note":"Azo-kleurstof in verband gebracht met hyperactiviteit; EU-waarschuwingsetiket verplicht.","detail":{"risks":"Een aardbeirode azo-kleurstof uit de \\"Southampton six\\", verboden in de VS. EFSA heeft de aanvaardbare inname in 2009 met een factor vier verlaagd.","benefits":"","interestingFact":"","research":""}},"e129":{"name":"Allurarood AC","note":"Azo-kleurstof in verband gebracht met hyperactiviteit; EU-waarschuwingsetiket verplicht.","detail":{"risks":"De meest gebruikte rode kleurstof in de VS, maar een EU-waarschuwingsetiket voor hyperactiviteit is verplicht. Recente muizenstudies stellen ook darmontstekingsverschijnselen bij hoge doses ter discussie.","benefits":"","interestingFact":"","research":""}},"e131":{"name":"Patentblauw V","note":"Synthetisch blauw; zeldzame allergische reacties.","detail":{"risks":"Een synthetische kleurstof die ook medisch wordt gebruikt om lymfeklieren te markeren tijdens operaties — waar het zeldzame allergische potentieel voor het eerst werd gedocumenteerd.","benefits":"","interestingFact":"","research":""}},"e132":{"name":"Indigotine","note":"Synthetisch blauw, over het algemeen goed verdragen.","detail":{"risks":"Het synthetische neefje van indigo, de kleurstof die spijkerbroeken kleurt. Slecht geabsorbeerd; EFSA vond geen veiligheidsrisico's bij de gerapporteerde innames.","benefits":"","interestingFact":"","research":""}},"e133":{"name":"Briljamtblauw FCF","note":"Synthetische kleurstof; over het algemeen goed verdragen bij voedingsdoses.","detail":{"risks":"Een triarylmethaanblauw dat vaak met tartrazine wordt gecombineerd om groen te maken. Minder dan 5% wordt opgenomen; de rest gaat er rechtstreeks doorheen.","benefits":"","interestingFact":"","research":""}},"e140":{"name":"Chlorofylen","note":"Natuurlijk groen plantenpigment.","detail":{"risks":"Hetzelfde molecuul dat bladeren groen maakt en fotosynthese aandrijft, geëxtraheerd uit gras, brandnetels of alfalfa.","benefits":"","interestingFact":"","research":""}},"e141":{"name":"Koperchlorofylinen","note":"Gestabiliseerd natuurlijk groen pigment.","detail":{"risks":"Chlorofyl waarvan de magnesiumkern is vervangen door koper, wat het groen stabiel houdt tijdens verhitting — het koper blijft gebonden en wordt niet opgenomen.","benefits":"","interestingFact":"","research":""}},"e142":{"name":"Groen S","note":"Synthetisch groen, beperkt in verschillende landen.","detail":{"risks":"Een synthetische kleurstof toegestaan in de EU (muntsaus, erwten in blik), maar verboden in Canada, Japan en Noorwegen. Slecht opgenomen.","benefits":"","interestingFact":"","research":""}},"e150a":{"name":"Gewone karamel","note":"Eenvoudige karamelkleurstof; de minst zorgwekkende karamelklasse.","detail":{"risks":"Gemaakt door suiker te verhitten, net zoals karamelliseren in een pan, maar dan industrieel gecontroleerd. De enige karamelklasse gemaakt zonder ammoniak- of sulfietchemie.","benefits":"","interestingFact":"","research":""}},"e150b":{"name":"Alkali-sulfietkaramel","note":"Karamel gemaakt met sulfietverbindingen.","detail":{"risks":"Karamel geproduceerd met sulfietverbindingen, gebruikt in sterke dranken zoals whisky en brandy. Resterend sulfiet is verwaarloosbaar.","benefits":"","interestingFact":"","research":""}},"e150c":{"name":"Ammoniakkaramel","note":"Bevat sporen van 4-MEI, ter discussie bij hoge innames.","detail":{"risks":"Karamel gemaakt met ammoniumverbindingen; het proces genereert sporen van 4-methylimidazool (4-MEI), wat tumoren veroorzaakte in muizenstudies met hoge doses. EFSA beoordeelt typische innames als veilig, maar heeft limieten gesteld.","benefits":"","interestingFact":"","research":""}},"e150d":{"name":"Sulfiet-ammoniakkaramel","note":"Cola-karamel; bevat sporen van 4-MEI, ter discussie bij hoge innames.","detail":{"risks":"'s Werelds meest geconsumeerde kleurstof in volume — het maakt cola bruin. Dezelfde 4-MEI-discussie als bij E150c; Californië eist kankerwaarschuwingen boven bepaalde niveaus, EFSA beschouwt normale consumptie als veilig.","benefits":"","interestingFact":"","research":""}},"e153":{"name":"Plantaardige koolstof","note":"Zwarte kleur; door EU beoordeeld, debat over nanodeeltjes.","detail":{"risks":"In feite koolstof van voedingskwaliteit. EFSA merkte op dat sommige batches nanodeeltjes bevatten die klein genoeg zijn om te worden opgenomen, wat leidde tot een lopende zuiverheidsbeoordeling.","benefits":"","interestingFact":"","research":""}},"e155":{"name":"Bruin HT","note":"Azo-bruin, verboden in verschillende landen.","detail":{"risks":"Een synthetisch azo-bruin gebruikt in chocoladecake; verboden in de VS, Canada en een groot deel van Scandinavië, maar binnen grenzen toegestaan in de EU.","benefits":"","interestingFact":"","research":""}},"e160a":{"name":"Carotenen","note":"Natuurlijk oranje pigment, provitamine A.","detail":{"risks":"Het pigment van wortels en pompoenen; je lichaam zet het naar behoefte om in vitamine A en slaat het overschot onschadelijk op in vet (eet er genoeg van en je huid wordt letterlijk oranje).","benefits":"","interestingFact":"","research":""}},"e160b":{"name":"Annatto","note":"Natuurlijke zaadkleurstof; zeldzame overgevoeligheidsreacties.","detail":{"risks":"Een oranjerood extract van de zaden van de orleaanboom, door de Azteken gebruikt als lichaamsverf en nu om cheddar en Red Leicester te meuren. Zeldzame overgevoeligheidsreacties zijn gedocumenteerd.","benefits":"","interestingFact":"","research":""}},"e160c":{"name":"Paprika-extract","note":"Natuurlijke kleurstof uit paprika.","detail":{"risks":"Geconcentreerd pigment uit zoete rode paprika's — dezelfde capsanthine die paprika rood maakt, min de pittigheid.","benefits":"","interestingFact":"","research":""}},"e160d":{"name":"Lycopeen","note":"Natuurlijk tomaatpigment.","detail":{"risks":"Het rood van tomaten en watermeloen; ook op zichzelf onderzocht als antioxidant.","benefits":"","interestingFact":"","research":""}},"e161b":{"name":"Luteïne","note":"Natuurlijk goudsbloempigment.","detail":{"risks":"Een geel carotenode uit goudsbloemblaadjes, identiek aan de luteïne die geconcentreerd aanwezig is in het netvlies van je oog.","benefits":"","interestingFact":"","research":""}},"e162":{"name":"Bietrood","note":"Natuurlijk bietenpigment.","detail":{"risks":"Betanine, geperst uit rode bieten. Zo onschadelijk dat de voornaamste \\"bijwerking\\" dezelfde is als die van rode bieten zelf.","benefits":"","interestingFact":"","research":""}},"e163":{"name":"Anthocyanen","note":"Natuurlijke bessen-/druivenpigmenten.","detail":{"risks":"De purperrode familie van pigmenten uit druivenschillen, bessen en rode kool. Ze veranderen van kleur met de zuurgraad — rood in zuur, blauw in alkalisch — wat verklaart waarom hetzelfde additief er in verschillende producten anders uit kan zien.","benefits":"","interestingFact":"","research":""}},"e170":{"name":"Calciumcarbonaat","note":"Krijt — mineraal wit, ook een calciumbron.","detail":{"risks":"Gewoon krijt/kalksteen, gebruikt als witte oppervlakkleurstof en anti-klontermiddel. Het is dezelfde verbinding als het calciumsupplement.","benefits":"","interestingFact":"","research":""}},"e171":{"name":"Titaandioxide","note":"Sinds 2022 verboden in EU-voeding — genotoxiciteit kon niet worden uitgesloten.","detail":{"risks":"Een helderwit mineraal pigment (ook in verf en zonnebrandcrème). EFSA kon DNA-schade door ophopende nanodeeltjes niet langer uitsluiten, en de EU verbood het in 2022 in levensmiddelen — nog steeds legaal in de VS.","benefits":"","interestingFact":"","research":""}},"e172":{"name":"IJzeroxiden","note":"Minerale pigmenten (roesttinten).","detail":{"risks":"Gezuiverd ijzeroxide — chemisch gezien gecontroleerde roest — dat gele, rode en zwarte tinten geeft. Vrijwel onoplosbaar en niet opgenomen.","benefits":"","interestingFact":"","research":""}},"e173":{"name":"Aluminium","note":"Metallische oppervlakkleur; zorg over aluminiuminname.","detail":{"risks":"Metallisch aluminium voor zilveren decoratie. Draagt bij aan de totale aluminiuminname via de voeding, waarvoor EFSA een strenge wekelijkse limiet hanteert omdat het zich opbouwt in het lichaam.","benefits":"","interestingFact":"","research":""}},"e174":{"name":"Zilver","note":"Decoratieve metallische kleur.","detail":{"risks":"Echt zilverblad, voornamelijk op suikerwerk (de zilveren bolletjes op taarten). Inert in de darm bij decoratiedoses.","benefits":"","interestingFact":"","research":""}},"e175":{"name":"Goud","note":"Decoratieve metallische kleur.","detail":{"risks":"Echt bladgoud. Chemisch inert — het gaat er in zijn geheel doorheen, wat het de duurste toevoeging maakt die precies niets doet.","benefits":"","interestingFact":"","research":""}},"e200":{"name":"Sorbinezuur","note":"Mild conserveermiddel; incidentele huidreacties.","detail":{"risks":"Voor het eerst geïsoleerd uit lijsterbessen; blokkeert de groei van schimmels en gisten door hun enzymen te verstoren. Je lichaam metaboliseert het zoals een vetzuur.","benefits":"","interestingFact":"","research":""}},"e201":{"name":"Natriumsorbaat","note":"Zout van sorbinezuur, mild conserveermiddel.","detail":{"risks":"De natriumvorm van sorbinezuur (oorspronkelijk afkomstig uit lijsterbessen). Het lost beter op in waterige voedingsmiddelen en werkt identiek: het blokkeert enzymen van schimmels en gisten.","benefits":"","interestingFact":"","research":""}},"e202":{"name":"Kaliumsorbaat","note":"Veelgebruikt mild conserveermiddel.","detail":{"risks":"Het werkpaard onder de conserveermiddelen voor kaas, wijn en bakwaren — een beter oplosbaar zout van sorbinezuur (oorspronkelijk uit lijsterbessen). Een van de best verdragen bekende conserveermiddelen.","benefits":"","interestingFact":"","research":""}},"e203":{"name":"Calciumsorbaat","note":"Zout van sorbinezuur, mild conserveermiddel.","detail":{"risks":"De calciumvorm van sorbinezuur, gebruikt wanneer een natriumvrij conserveermiddel gewenst is. Wordt net als de rest van de sorbaatfamilie gemetaboliseerd als een vetzuur.","benefits":"","interestingFact":"","research":""}},"e210":{"name":"Benzoëzuur","note":"Kan met vitamine C benzeen vormen; allergietrigger.","detail":{"risks":"Komt van nature voor in veenbessen en kaneel; blokkeert gisten en bacteriën in zure voedingsmiddelen. Het addertje onder het gras: in combinatie met vitamine C in frisdranken kan het sporen van benzeen vormen, een bekende kankerverwekkende stof — de reden dat recepturen in de jaren 2000 werden aangepast.","benefits":"","interestingFact":"","research":""}},"e211":{"name":"Natriumbenzoaat","note":"Kan met vitamine C benzeen vormen; in combinatie met kleurstof in verband gebracht met hyperactiviteit.","detail":{"risks":"Het oplosbare zout van benzoëzuur, de standaard in frisdranken. De Southampton-studie testte het samen met azokleurstoffen en vond in combinatie effecten op hyperactiviteit; het benzeen-met-vitamine C-probleem geldt ook hier.","benefits":"","interestingFact":"","research":""}},"e212":{"name":"Kaliumbenzoaat","note":"Benzoaatconserveermiddel; dezelfde benzeen/vitamine C-zorg.","detail":{"risks":"De kaliumvorm van natriumbenzoaat, gekozen voor natriumarme recepturen. Dezelfde chemie: effectief tegen gisten in zure dranken, dezelfde waarschuwing voor benzeenvorming met vitamine C.","benefits":"","interestingFact":"","research":""}},"e213":{"name":"Calciumbenzoaat","note":"Benzoaatconserveermiddel; dezelfde benzeen/vitamine C-zorg.","detail":{"risks":"De calciumvorm van de benzoaatfamilie, zelden gebruikt. Deelt de eigenschappen van de familie — werkt alleen in zure voedingsmiddelen en draagt de vitamine C/benzeen-waarschuwing.","benefits":"","interestingFact":"","research":""}},"e214":{"name":"Ethylparabeen","note":"Parabeenconserveermiddel; hormoonontregelingsdebat.","detail":{"risks":"Een van de weinige parabenen die nog zijn toegestaan in voeding (zelden gebruikt). Parabenen bootsen in labstudies zwak oestrogeen na, waardoor ze onder de loup liggen vanwege mogelijke hormoonontregeling.","benefits":"","interestingFact":"","research":""}},"e218":{"name":"Methylparabeen","note":"Parabeenconserveermiddel; hormoonontregelingsdebat.","detail":{"risks":"Een parabeenconserveermiddel dat bekender is uit cosmetica, soms gebruikt in glazuur voor suikerwerk. De kwestie rond hormoonontregeling — zwakke oestrogeenimitatie in labstudies — geldt voor de gehele parabeenfamilie.","benefits":"","interestingFact":"","research":""}},"e219":{"name":"Natriummethylparabeen","note":"Parabeenconserveermiddel; hormoonontregelingsdebat.","detail":{"risks":"Het wateroplosbare natriumzout van methylparabeen. Dezelfde familie, hetzelfde kritische onderzoek naar hormoonontregeling.","benefits":"","interestingFact":"","research":""}},"e220":{"name":"Zwavel-dioxide","note":"Sulfiet — een belangrijk allergeen, vernietigt vitamine B1.","detail":{"risks":"Het eeuwenoude conserveermiddel voor wijn — de Romeinen brandden zwavelkaarsen in vaten. Het stopt verbruining en microben, maar is een echt allergeen: ongeveer 3–10% van de astmapatiënten reageert erop, wat de reden is dat \\"bevat sulfieten\\" een verplichte vermelding is. Het vernietigt ook thiamine (vitamine B1) in voeding.","benefits":"","interestingFact":"","research":""}},"e221":{"name":"Natriumsulfiet","note":"Sulfietallergeen.","detail":{"risks":"Een sulfietzout dat dezelfde actieve SO₂ vrijgeeft als E220 — dezelfde antimicrobiële kracht, dezelfde waarschuwing voor astmagevoeligheid, dezelfde verplichte allergeenetikettering.","benefits":"","interestingFact":"","research":""}},"e222":{"name":"Natriumbisulfiet","note":"Sulfietallergeen.","detail":{"risks":"Een lid van de sulfietfamilie gebruikt in wijn en ingelegde voedingsmiddelen. Alle sulfieten delen de allergeenwaarschuwing en de vernietiging van vitamine B1 van E220.","benefits":"","interestingFact":"","research":""}},"e223":{"name":"Natriummetabisulfiet","note":"Sulfietallergeen.","detail":{"risks":"De poedervorm van zwaveldioxidechemie, veelvoorkomend in gedroogd fruit en wijn. Dezelfde allergeenwaarschuwing als E220 — gedroogde abrikozen blijven er oranje door.","benefits":"","interestingFact":"","research":""}},"e224":{"name":"Kaliummetabisulfiet","note":"Sulfietallergeen.","detail":{"risks":"De \\"campdentablet\\" van de wijnmaker — het standaard sulfiet voor thuis- en commerciële wijnproductie. Dezelfde waarschuwingen voor allergenen en B1 als de rest van de familie.","benefits":"","interestingFact":"","research":""}},"e226":{"name":"Calciumsulfiet","note":"Sulfietallergeen.","detail":{"risks":"Een zelden gebruikt calciumzout van de sulfietfamilie; deelt de waarschuwing voor astmagevoeligheid en de verplichte etikettering van de groep.","benefits":"","interestingFact":"","research":""}},"e228":{"name":"Kaliumbisulfiet","note":"Sulfietallergeen.","detail":{"risks":"Een sulfiet dat voornamelijk in wijn wordt gebruikt. Dezelfde familiechemie en allergeenwaarschuwing als E220.","benefits":"","interestingFact":"","research":""}},"e234":{"name":"Nisine","note":"Natuurlijk antibacterieel peptide uit fermentatie.","detail":{"risks":"Een peptide dat wordt geproduceerd door dezelfde bacteriën die melk fermenteren — het slaat gaatjes in de membranen van bederfbacteriën. Gebruikt in kaas en blikvoedsel; wordt verteerd als elk ander eiwit.","benefits":"","interestingFact":"","research":""}},"e235":{"name":"Natamysine","note":"Schimmelwerend middel voor kaaskorsten; debat over antibioticaklasse.","detail":{"risks":"Een schimmelwerend middel afkomstig van bodembacteriën, aangebracht op kaaskorsten en droge worstenhuiden. Wordt nauwelijks opgenomen, maar het medisch gebruik als antischimmelmiddel houdt een debat over resistentie in stand.","benefits":"","interestingFact":"","research":""}},"e239":{"name":"Hexamethyleentetramine","note":"Formaldehyde-afgevend conserveermiddel (alleen Provolone).","detail":{"risks":"In de EU alleen toegestaan voor Provolone-kaas. Het werkt door langzaam formaldehyde af te geven — de reden dat het gebruik zo strikt beperkt is.","benefits":"","interestingFact":"","research":""}},"e242":{"name":"Dimethyldicarbonaat","note":"Sterilisatiemiddel voor dranken dat volledig afbreekt.","detail":{"risks":"Vlak voor het gebotteld wordt in dranken geïnjecteerd; het doodt microben en hydrolyseert daarna binnen enkele uren volledig in kleine hoeveelheden methanol en CO₂ — er blijft niets van over tegen de tijd dat u het drinkt.","benefits":"","interestingFact":"","research":""}},"e249":{"name":"Kaliumnitriet","note":"Nitriet voor bewerkt vlees; vormt nitrosaminen, door IARC geclassificeerde route.","detail":{"risks":"De kaliumtweeling van natriumnitriet (E250): houdt bewerkt vlees roze en vrij van botulisme, maar voedt dezelfde nitrosaminechemie die ten grondslag ligt aan de IARC-classificatie van bewerkt vlees.","benefits":"","interestingFact":"","research":""}},"e250":{"name":"Natriumnitriet","note":"Nitriet voor bewerkt vlees; vormt kankerverwekkende nitrosaminen (IARC).","detail":{"risks":"Wat ham roze maakt en botulisme blokkeert — de dodelijkste bekende toxine — en dat is waarom het nog steeds is toegestaan. Maar met vleeseiwitten en hitte vormt het nitrosaminen, wat essentieel is voor de reden waarom IARC bewerkt vlees classificeert als kankerverwekkend voor mensen. Frankrijk is in 2023 begonnen met het beperken ervan.","benefits":"","interestingFact":"","research":""}},"e251":{"name":"Natriumnitraat","note":"Wordt omgezet in nitriet; dezelfde zorg over nitrosaminen.","detail":{"risks":"De opslagvorm van pekelchemie: bacteriën in het vlees (en je speeksel) zetten nitraat geleidelijk om in nitriet, wat dezelfde nitrosamineroute voedt als E250.","benefits":"","interestingFact":"","research":""}},"e252":{"name":"Kaliumnitraat","note":"Wordt omgezet in nitriet; dezelfde zorg over nitrosaminen.","detail":{"risks":"Salpeter — al sinds de middeleeuwen gebruikt om vlees te pekelen (en om buskruit te maken). Bacteriën zetten het in het vlees om in nitriet, waar de nitrosaminechemie begint.","benefits":"","interestingFact":"","research":""}},"e260":{"name":"Azijnzuur","note":"Azijn.","detail":{"risks":"Geconcentreerd azijnzuur. Een van de oudste conserveermiddelen in de menselijke geschiedenis.","benefits":"","interestingFact":"","research":""}},"e261":{"name":"Kaliumacetaat","note":"Azijnzout.","detail":{"risks":"Het zuur van azijn gebonden aan kalium — een zuurteregelaar die je lichaam precies zo verwerkt als azijn.","benefits":"","interestingFact":"","research":""}},"e262":{"name":"Natriumacetaten","note":"Azijnzout — de smaak van salt & vinegar-chips.","detail":{"risks":"Natriumacetaat geeft salt & vinegar-chips hun pittige smaak zonder dat ze soppig worden. Het is ook de verbinding in herbruikbare handwarmers.","benefits":"","interestingFact":"","research":""}},"e263":{"name":"Calciumacetaat","note":"Azijnzout.","detail":{"risks":"Azijnzuur gebonden aan calcium; dient ook als stevigheidscomponent. Wordt net als azijn gemetaboliseerd.","benefits":"","interestingFact":"","research":""}},"e270":{"name":"Melkzuur","note":"Natuurlijk fermentatiezuur.","detail":{"risks":"Het zuur van yoghurt, zuurdesem en spierpijn — geproduceerd door fermentatie. Melkzuur van levensmiddelenkwaliteit is afkomstig van de fermentatie van suiker met dezelfde bacteriënfamilie als in yoghurt.","benefits":"","interestingFact":"","research":""}},"e280":{"name":"Propionzuur","note":"Broodconserveermiddel; ter discussie staande darmeffecten bij hoge doses.","detail":{"risks":"Komt van nature voor in gatenkaas (het zorgt voor de smaak van de gaten) en in je eigen darmen, waar bacteriën het produceren uit vezels. Als broodconserveermiddel stopt het schimmel; kleine onderzoeken bediscussiëren metabole effecten bij hoge doses.","benefits":"","interestingFact":"","research":""}},"e281":{"name":"Natriumpropionaat","note":"Schimmelremmer voor brood.","detail":{"risks":"Het natriumzout van propionzuur — de verbinding die je eigen darmbacteriën uit vezels maken, die hier verpakt brood wekenlang schimmelvrij houdt.","benefits":"","interestingFact":"","research":""}},"e282":{"name":"Calciumpropionaat","note":"Broodconserveermiddel; ter discussie staande darmeffecten bij hoge doses.","detail":{"risks":"Het meest voorkomende broodconserveermiddel ter wereld. Chemisch gezien hetzelfde propionaat dat je darmen uit vezels produceren; een paar kleine onderzoeken bediscussiëren effecten op de eetlust en de stofwisseling bij hoge innames.","benefits":"","interestingFact":"","research":""}},"e283":{"name":"Kaliumpropionaat","note":"Schimmelremmer voor brood.","detail":{"risks":"De kaliumvorm van de propionaatfamilie, voor natriumarm brood. Hetzelfde schimmelblokkerende mechanisme.","benefits":"","interestingFact":"","research":""}},"e284":{"name":"Boorzuur","note":"In de EU alleen toegestaan voor kaviaar.","detail":{"risks":"Een oud conserveermiddel dat nu in alle EU-voedingsmiddelen is verboden, op één na: echte steerkaviaar, waar geen enkel alternatief de eitjes goed conserveert. Beperkt omdat boor zich opbouwt in het lichaam.","benefits":"","interestingFact":"","research":""}},"e285":{"name":"Borax","note":"Slechts toegestaan voor kaviaar in de EU.","detail":{"risks":"Het natriumzout van boorzuur, dat de enige EU-uitzondering deelt: steurkaviaar. Overal elders is het een ingrediënt voor schoonmaakmiddelen, niet voor voeding.","benefits":"","interestingFact":"","research":""}},"e290":{"name":"Koolstofdioxide","note":"De bubbels in koolzuurhoudende dranken.","detail":{"risks":"Gewoon CO₂ — hetzelfde gas dat je uitademt. In dranken lost het op als koolzuur, wat zorgt voor de prik en de tinteling op je tong; in verpakkingen verdringt het zuurstof zodat voedsel minder snel bederft. Het verlaat je lichaam met een boer.","benefits":"","interestingFact":"","research":""}},"e296":{"name":"Appelzuur","note":"Natuurlijk fruitzuur.","detail":{"risks":"Het friszure zuur uit groene appels — de naam komt van malum, Latijn voor appel. Ook de zure kick in extreem zuur snoepgoed.","benefits":"","interestingFact":"","research":""}},"e297":{"name":"Fumaarzuur","note":"Natuurlijk fruitachtig zuur.","detail":{"risks":"Komt natuurlijk voor in eekhoorntjesbrood en korstmossen; wordt gebruikt waar appel- of citroenzuur te veel vocht zou opnemen, bijv. in poedermixen.","benefits":"","interestingFact":"","research":""}},"e300":{"name":"Ascorbinezuur","note":"Vitamine C.","detail":{"risks":"Zuiver vitamine C. In voeding werkt het als zuurstofvanger — het offert zichzelf op aan oxidatie zodat het voedsel niet verbruint. In brood versterkt het de gluten.","benefits":"","interestingFact":"","research":""}},"e301":{"name":"Natriumascorbaat","note":"Vitamine C-zout.","detail":{"risks":"Vitamine C gebonden aan natrium voor een betere oplosbaarheid — standaard in bewerkt vlees, waar het de pekeling versnelt en de vorming van nitrosaminen onderdrukt.","benefits":"","interestingFact":"","research":""}},"e302":{"name":"Calciumascorbaat","note":"Vitamine C-zout.","detail":{"risks":"Vitamine C in zijn mildere calciumvorm, gebruikt om te voorkomen dat gesneden fruit verbruint. Voedingskundig gezien is het nog steeds gewoon vitamine C plus een beetje calcium.","benefits":"","interestingFact":"","research":""}},"e304":{"name":"Ascorbylpalmitaat","note":"Vetoplosbare vitamine C.","detail":{"risks":"Vitamine C gebonden aan een vetzuur zodat het oliën en vetten kan beschermen tegen ranzigheid, waar gewone vitamine C niet bij kan.","benefits":"","interestingFact":"","research":""}},"e306":{"name":"Tocoferolen","note":"Vitamine E.","detail":{"risks":"Natuurlijke vitamine E geëxtraheerd uit plantaardige oliën; beschermt vetten tegen ranzig worden op dezelfde manier als het je celmembranen beschermt.","benefits":"","interestingFact":"","research":""}},"e307":{"name":"Alfatocoferol","note":"Vitamine E.","detail":{"risks":"De specifieke vorm van vitamine E waar je lichaam de voorkeur aan geeft, synthetisch gemaakt voor consistentie. Dezelfde werking als antioxidant als E306.","benefits":"","interestingFact":"","research":""}},"e308":{"name":"Gammatocoferol","note":"Vitamine E.","detail":{"risks":"De vitamine E-vorm die het meest voorkomt in soja- en maisolie, die vetten beschermt tegen oxidatie.","benefits":"","interestingFact":"","research":""}},"e309":{"name":"Deltatocoferol","note":"Vitamine E.","detail":{"risks":"De meest hittebestendige uit de vitamine E-familie, favoriet voor frituurvetten.","benefits":"","interestingFact":"","research":""}},"e310":{"name":"Propylgallaat","note":"Synthetische antioxidant; hormoondebat.","detail":{"risks":"Een synthetische antioxidant voor vetten en oliën. Onderzoek bij knaagdieren riep (betwiste) vragen op over hormonen en tumoren; EFSA stelde in 2014 de innamelimiet opnieuw vast, en het komt steeds minder voor in moderne recepten.","benefits":"","interestingFact":"","research":""}},"e311":{"name":"Octylgallaat","note":"Synthetische antioxidant; beperkte gegevens.","detail":{"risks":"Een gallaat-antioxidant waarvan de EU-toelating in 2018 is vervallen wegens een gebrek aan veiligheidsgegevens — als je het op een etiket ziet, betekent dit meestal een oude formulering of import.","benefits":"","interestingFact":"","research":""}},"e312":{"name":"Dodecylgallaat","note":"Synthetische antioxidant; beperkte gegevens.","detail":{"risks":"Het gallaat met de langste keten; net als bij E311 werd de EU-toelating in 2018 ingetrokken toen producenten geen ondersteunende gegevens indienden.","benefits":"","interestingFact":"","research":""}},"e315":{"name":"Erythorbinezuur","note":"Vitamine C-spiegelmolecule, alleen antioxidant.","detail":{"risks":"Een spiegelbeeld-isomeer van vitamine C: dezelfde antioxidantkracht in voeding, maar vrijwel geen vitamine-activiteit in het lichaam.","benefits":"","interestingFact":"","research":""}},"e316":{"name":"Natriumerythorbaat","note":"Antioxidant gebruikt in bewerkt vlees.","detail":{"risks":"Versnelt de pekeling en vermindert de hoeveelheid nitriet die nodig is in bewerkt vlees — de aanwezigheid ervan betekent meestal minder nitriet, niet meer risico. De oude mythe dat het \\"van regenwormen is gemaakt\\" is precies dat, een mythe (het wordt gemaakt van suiker).","benefits":"","interestingFact":"","research":""}},"e319":{"name":"TBHQ","note":"Synthetische antioxidant; onderzoeken naar effecten op het immuunsysteem betwist.","detail":{"risks":"Tert-butylhydrochinon, een uit aardolie gewonnen antioxidant in frituuroliën en instant noodles. Dierstudies met hoge doseringen bediscussiëren effecten op het immuunsysteem en tumoren; EFSA hanteert een strenge innamelimiet.","benefits":"","interestingFact":"","research":""}},"e320":{"name":"BHA","note":"Mogelijk kankerverwekkend (IARC 2B); zorgen over de hormoonhuishouding.","detail":{"risks":"Butylhydroxyanisol, een synthetische antioxidant. IARC classificeert het als \\"mogelijk kankerverwekkend\\" op basis van voormaagtumoren bij knaagdieren; het staat ook op de EU-screeningslijst voor hormoonontregelende stoffen. Vitamine E doet hetzelfde werk.","benefits":"","interestingFact":"","research":""}},"e321":{"name":"BHT","note":"Betwiste kankerverwekkendheid en hormoonontregelende effecten.","detail":{"risks":"Het chemische broertje van BHA, ook gebruikt in cosmetica en kerosine. Bewijs is verdeelder dan voor BHA — sommige onderzoeken suggereren zelfs beschermende effecten — maar door het hormoondebat blijft het een punt van zorg.","benefits":"","interestingFact":"","research":""}},"e322":{"name":"Lecithinen","note":"Natuurlijke emulgator uit soja of zonnebloem.","detail":{"risks":"Het molecuul dat vet en water laat mengen — de ene kant houdt van water, de andere van olie. Geëxtraheerd uit sojabonen, zonnebloempitten of eigeel (mayonaise werkt dankzij eilecithine). Je eigen celmembranen zijn er gedeeltelijk uit opgebouwd.","benefits":"","interestingFact":"","research":""}},"e325":{"name":"Natriumlactaat","note":"Zout van melkzuur.","detail":{"risks":"Fermentatiezuur gebonden aan natrium — een vochtvasthouder en mild conserveringsmiddel in vlees en bakkerijproducten. Je spieren maken hetzelfde lactaat aan tijdens het sporten.","benefits":"","interestingFact":"","research":""}},"e326":{"name":"Kaliumlactaat","note":"Zout van melkzuur.","detail":{"risks":"De kaliumvorm van lactaat, veelvoorkomend in natriumarme vleesproducten. Wordt op dezelfde manier verwerkt als het lactaat dat je eigen lichaam aanmaakt.","benefits":"","interestingFact":"","research":""}},"e327":{"name":"Calciumlactaat","note":"Zout van melkzuur, ook een calciumbron.","detail":{"risks":"Melkzuur met calcium — gebruikt om groenten in blik stevig te houden en zelfs om voedingsmiddelen te verrijken met calcium. Het is het knapperige kristal dat je soms ziet op oude cheddar.","benefits":"","interestingFact":"","research":""}},"e330":{"name":"Citroenzuur","note":"Alomtegenwoordig natuurlijk zuur.","detail":{"risks":"Het zuur van citroenen, industrieel geproduceerd door suiker te fermenteren met een schimmel (een proces ontdekt in 1917). Elke cel in je lichaam maakt en verbrandt continu citroenzuur — de \\"citroenzuurcyclus\\" is hoe je energie genereert. Het hardnekkige gerucht dat \\"E330 kanker veroorzaakt\\" gaat terug op een neppetiket uit de jaren 1970, een van de oudste stukken desinformatie over voeding.","benefits":"","interestingFact":"","research":""}},"e331":{"name":"Natriumcitraten","note":"Zout van citroenzuur.","detail":{"risks":"Het zout van citroenzuur — dit zorgt ervoor dat smeltkaas gelijkmatig smelt in plaats van schift, door het calcium dat caseïne-eiwitten bij elkaar houdt losser te maken.","benefits":"","interestingFact":"","research":""}},"e332":{"name":"Kaliumcitraten","note":"Zout van citroenzuur.","detail":{"risks":"Citraat met kalium in plaats van natrium; een zuurtegraadbuffer die in dezelfde energiecyclus wordt verwerkt als citroenzuur zelf.","benefits":"","interestingFact":"","research":""}},"e333":{"name":"Calciumcitraten","note":"Zout van citroenzuur, ook een calciumbron.","detail":{"risks":"Citraat gebonden aan calcium — zuurteregelaar, verstevigingsmiddel en de calciumvorm die in veel supplementen wordt gebruikt omdat het goed wordt opgenomen.","benefits":"","interestingFact":"","research":""}},"e334":{"name":"Wijnsteenzuur","note":"Natuurlijk druivenzuur.","detail":{"risks":"Het zuur van druiven en wijn — de kristallen die je soms onderin een wijnfles vindt, zijn het kaliumzout ervan. Het klassieke zuur in bakpoeder.","benefits":"","interestingFact":"","research":""}},"e335":{"name":"Natriumtartraten","note":"Zout van druivenzuur.","detail":{"risks":"Druivenzuur gebonden aan natrium, een zuurteregelaar die meestal wordt gezien in jam en gelei. Wordt grotendeels niet opgenomen.","benefits":"","interestingFact":"","research":""}},"e336":{"name":"Kaliumtartraten","note":"Wijnsteen.","detail":{"risks":"Wijnsteen — letterlijk afgeschraapt van de binnenkant van wijnvaten. De traditionele partner van baksoda in bakpoeder en de stabilisator van stijfgeslagen eiwit.","benefits":"","interestingFact":"","research":""}},"e337":{"name":"Natriumkaliumtartraat","note":"Rochellesout, afkomstig uit de wijnmakerij.","detail":{"risks":"Rochellesout, voor het eerst gemaakt door een Franse apotheker in 1675. Een beroemdheid binnen de kristallografie (het was het eerste materiaal dat piëzo-elektrisch bleek te zijn) dat in alle stilte werk verricht als zuurteregelaar.","benefits":"","interestingFact":"","research":""}},"e338":{"name":"Fosforzuur","note":"Colazuur; hoge fosfaatinname gelinkt aan cardiovasculaire problemen.","detail":{"risks":"Wat cola zijn scherpe smaak geeft (en zijn feesttrucje om roest te verwijderen). De zorg is niet zozeer acute toxiciteit, maar de totale fosfaatbelasting: de herbeoordeling van de EFSA uit 2019 wees uit dat grote consumenten de veilige inname kunnen overschrijden, en een overschot aan fosfaat wordt in verband gebracht met belasting van vaten en nieren.","benefits":"","interestingFact":"","research":""}},"e339":{"name":"Natriumfosfaten","note":"Hoge fosfaatinname gelinkt aan cardiovasculaire problemen.","detail":{"risks":"Veelzijdige fosfaatzouten — vochtbinding, smelting, buffering. Afzonderlijk veilig, maar ze stapelen op: de herbeoordeling van de EFSA uit 2019 waarschuwde dat de totale fosfaatinname uit bewerkt voedsel de veilige niveaus kan overschrijden.","benefits":"","interestingFact":"","research":""}},"e340":{"name":"Kaliumfosfaten","note":"Zorgen over hoge fosfaatinname.","detail":{"risks":"De kaliumtak van de fosfaatfamilie, veelvoorkomend in sportdranken en smeltkaas. Waarschuwt voor dezelfde cumulatieve fosfaatbelasting als zijn verwanten.","benefits":"","interestingFact":"","research":""}},"e341":{"name":"Calciumfosfaten","note":"Fosfaat; matige inname acceptabel.","detail":{"risks":"Het mineraal waar je botten en tanden uit bestaan, gebruikt als rijsmiddel en calciumverrijker. Het zachtste lid van de fosfaatfamilie — het calcium compenseert de bezorgdheid over de fosfaatbelasting gedeeltelijk.","benefits":"","interestingFact":"","research":""}},"e343":{"name":"Magnesiumfosfaten","note":"Fosfaat; matige inname acceptabel.","detail":{"risks":"Fosfaat dat magnesium bevat, gebruikt als antiklontermiddel en zuurteregelaar. Draagt bij aan de fosfaatbelasting, maar de typische gebruikte hoeveelheden zijn minuscuul.","benefits":"","interestingFact":"","research":""}},"e350":{"name":"Natriummalaten","note":"Zout van appelzuur.","detail":{"risks":"Appelzuur gebonden aan natrium — een zuurtebuffer die op dezelfde manier wordt gemetaboliseerd als het appelzuur in elke appel.","benefits":"","interestingFact":"","research":""}},"e351":{"name":"Kaliummalaat","note":"Zout van appelzuur.","detail":{"risks":"De kaliumvorm van appelzuur, een zelden gebruikte zuurteregelaar zonder bekende problemen.","benefits":"","interestingFact":"","research":""}},"e352":{"name":"Calciummalaten","note":"Zout van appelzuur.","detail":{"risks":"Appelzuur dat calcium bevat; zuurteregelaar en verstevigingsmiddel, gemetaboliseerd zoals fruitzuur.","benefits":"","interestingFact":"","research":""}},"e353":{"name":"Metawijnsteenzuur","note":"Wijnstabilisator uit druivenzuur.","detail":{"risks":"Druivenzuurmoleculen die aan elkaar zijn gekoppeld tot korte ketens; wijnmakers voegen het toe om te voorkomen dat er onschadelijke tartraatkristallen in de fles ontstaan. Het verandert langzaam weer in gewoon wijnsteenzuur.","benefits":"","interestingFact":"","research":""}},"e355":{"name":"Adipinezuur","note":"Synthetisch wrang zuur voor poeders.","detail":{"risks":"Een wrang zuur dat bestand is tegen vocht, waardoor het ideaal is voor poederdrankmixen en puddingpoeder. Industrieel is het bekender als grondstof voor nylon; het gebruik in voeding is een afrondingsfout van de productie.","benefits":"","interestingFact":"","research":""}},"e363":{"name":"Barnsteenzuur","note":"Fermentatiezuur.","detail":{"risks":"Een zuur uit dezelfde energiecyclus als citraat — je cellen maken het voortdurend aan. In voeding geeft het poederdesserts een frissere smaak; de naam komt van barnsteen (succinum), waaruit het voor het eerst werd gedistilleerd.","benefits":"","interestingFact":"","research":""}},"e380":{"name":"Triammoniumcitraat","note":"Citraat-zuurteregelaar.","detail":{"risks":"Citroenzuur geneutraliseerd met ammonium, gebruikt om de zuurgraad in smeltkaas te bufferen. Het ammonium draait gewoon mee in de normale stikstofverwerking van je lichaam.","benefits":"","interestingFact":"","research":""}},"e385":{"name":"Calcium-dinatrium-EDTA","note":"Chelator; zorgen over mineraalabsorptie bij hoge doses.","detail":{"risks":"Een moleculaire klauw die sporenmetalen vastgrijpt zodat ze geen ranzigheid of verkleuring kunnen katalyseren (het houdt kikkererwten in blik bleek). Diezelfde greep kan zich binden aan mineralen uit de voeding, vandaar de doseringslimieten. Wordt medisch ook gebruikt bij zwaremetalenvergiftiging.","benefits":"","interestingFact":"","research":""}},"e392":{"name":"Rosmarijnextract","note":"Natuurlijk kruidenantioxidant.","detail":{"risks":"Geconcentreerde antioxidanten (carnosinezuur) uit rosmijnbladeren — de moderne clean-labelvervanger voor BHA/BHT.","benefits":"","interestingFact":"","research":""}},"e400":{"name":"Algininezuur","note":"Verdikkingsmiddel uit bruinwier.","detail":{"risks":"De structurele gom van bruine kelp — wat zeewier onder water buigzaam houdt. In je darmen gedraagt het zich als oplosbare vezel.","benefits":"","interestingFact":"","research":""}},"e401":{"name":"Natriumalginaat","note":"Verdikkingsmiddel uit zeewier.","detail":{"risks":"Uit bruine kelp; beroemd als het \\"sferificatie\\"-ingrediënt uit de moleculaire gastronomie dat vloeistoffen verandert in kaviaarachtige parels. Ook de gel in veel middelen tegen maagzuur.","benefits":"","interestingFact":"","research":""}},"e402":{"name":"Kaliumalginaat","note":"Verdikkingsmiddel uit zeewier.","detail":{"risks":"De kaliumvorm van kelpalginaat; een verdikkingsmiddel op basis van oplosbare vezels zonder bekende problemen.","benefits":"","interestingFact":"","research":""}},"e404":{"name":"Calciumalginaat","note":"Geliermiddel uit zeewier.","detail":{"risks":"Kelpalginaat voorgeladen met het calcium dat het laat gelieren — vanwege hetzelfde geliertrucje ook gebruikt in wondverbanden.","benefits":"","interestingFact":"","research":""}},"e405":{"name":"Propyleenglycolalginaat","note":"Gemodificeerd zeewierverdikkingsmiddel (bierschuim, dressings).","detail":{"risks":"Kelpalginaat gemodificeerd om zuur te overleven — dit is wat bierschuim overeind houdt en saladedressing dik maakt. Het propyleenglycoldeel komt vrij en wordt onschadelijk gemetaboliseerd.","benefits":"","interestingFact":"","research":""}},"e406":{"name":"Agaragar","note":"Geliermiddel uit zeewier.","detail":{"risks":"Uit roodwieren — ontdekt in Japan in 1658, en de standaardgelei in microbiologische laboratoria wereldwijd. Stijft steviger op dan gelatine en blijft op kamertemperatuur stevig; volledig plantaardig.","benefits":"","interestingFact":"","research":""}},"e407":{"name":"Carrageen","note":"Betwiste link met darmontsteking in gedegradeerde vorm.","detail":{"risks":"Gewonnen uit Iers mos (zeewier), al eeuwenlang gebruikt in Ierse melkpudding. Het debat: gedegradeerd carrageen (niet de voedingsgeschikte vorm) veroorzaakt darmontsteking bij dieren, en het blijft omstreden of maagzuur de voedingsvorm afbreekt. EFSA hernieuwde de goedkeuring in 2018, maar vroeg om meer gegevens.","benefits":"","interestingFact":"","research":""}},"e407a":{"name":"Verwerkt eucheuma-zeewier","note":"Halfgezuiverd carrageen; hetzelfde debat.","detail":{"risks":"Een minder gezuiverd carrageen dat rechtstreeks afkomstig is van gekweekt eucheuma-zeewier, waarbij wat cellulose behouden blijft. Het deelt het debat over carrageendegradatie punt voor punt.","benefits":"","interestingFact":"","research":""}},"e410":{"name":"Johannesbroodpitmeel","note":"Natuurlijk verdikkingsmiddel uit johannesbrood.","detail":{"risks":"Gemalen zaden van de johannesbroodboom. Leuk weetje: het gelijkmatige gewicht van johannesbroodzaden gaf ons de juweliersmaat \\"karaat\\".","benefits":"","interestingFact":"","research":""}},"e412":{"name":"Guarpitmeel","note":"Natuurlijk verdikkingsmiddel.","detail":{"risks":"Gemalen guarbonen uit India — acht keer de verdikkingskracht van maïzena. Het is oplosbare vezel; zeer grote hoeveelheden werken als elk overschot aan vezels.","benefits":"","interestingFact":"","research":""}},"e413":{"name":"Tragacant","note":"Natuurlijke boomsapgom.","detail":{"risks":"Gedroogd sap van Midden-Oosten astragalusstruiken, al sinds de oudheid geoogst — Theophrastus beschreef het in 300 BC. De traditionele versteviger van suikerwerkbloemen op bruidstaarten.","benefits":"","interestingFact":"","research":""}},"e414":{"name":"Acaciagom","note":"Natuurlijke gom arabica.","detail":{"risks":"Sap van de acaciaboom, geoogst zoals esdoornsiroop, voornamelijk in Soedan. Het is wat citrusoliën in frisdrank zwevend houdt en winegums hun bite geeft. Telt mee als oplosbare vezel.","benefits":"","interestingFact":"","research":""}},"e415":{"name":"Xanthaangom","note":"Verdikkingsmiddel uit fermentatie.","detail":{"risks":"Geproduceerd door suiker te fermenteren met Xanthomonas-bacteriën. De superkracht is \\"shear thinning\\": dik in rust, vloeibaar bij schudden — de reden waarom saladedressing schenkt maar niet ontmengt. Onmisbaar bij glutenvrij bakken.","benefits":"","interestingFact":"","research":""}},"e416":{"name":"Karayagom","note":"Boomgom; mild laxerend bij hoge doses.","detail":{"risks":"Sap van de Indiase sterculiaboom. Grotendeels onverteerbare vezels — wat ook de reden is waarom grote hoeveelheden een laxerend effect hebben.","benefits":"","interestingFact":"","research":""}},"e417":{"name":"Taragom","note":"Natuurlijk verdikkingsmiddel uit zaden.","detail":{"risks":"Gemalen zaden van de Peruaanse taraboom — een mildere neef van guar- en johannesbroodpitmeel, die zich gedraagt als oplosbare vezel.","benefits":"","interestingFact":"","research":""}},"e418":{"name":"Gellaangom","note":"Geliermiddel uit fermentatie.","detail":{"risks":"Gemaakt door bacteriële fermentatie zoals xanthaan, maar het geliert in plaats van verdikt — het is wat het vruchtvlees zwevend houdt in sommige sappen en veganistische gelei opstijft met een opmerkelijk strakke bite.","benefits":"","interestingFact":"","research":""}},"e420":{"name":"Sorbitol","note":"Polyol-zoetstof; laxerend bij hoge doses.","detail":{"risks":"Een suikeralcohol die natuurlijk voorkomt in lijsterbessen en peren. Bevat de helft van de calorieën van suiker en is tandvriendelijk, maar niet-opgenomen sorbitol fermenteert in de dikke darm — de reden waarom verpakkingen van suikervrije kauwgom waarschuwen voor laxerende effecten.","benefits":"","interestingFact":"","research":""}},"e421":{"name":"Mannitol","note":"Polyol; laxerend bij hoge doses.","detail":{"risks":"Een suikeralcohol die oorspronkelijk werd gewonnen uit de manna-es (vandaar de bijbelse naam). Wordt nauwelijks opgenomen, dus de standaard spijsverteringswaarschuwing voor polyolen geldt; de verkoelende smelt zorgt voor de frisheid in sommige pepermuntjes.","benefits":"","interestingFact":"","research":""}},"e422":{"name":"Glycerol","note":"Bevochtigingsmiddel dat voeding vochtig houdt.","detail":{"risks":"De ruggengraatmolecuul van alle vetten, die vrijkomt wanneer vet wordt verteerd. In voeding houdt het vocht vast — het is de reden waarom eiwitrepen maandenlang chewy blijven.","benefits":"","interestingFact":"","research":""}},"e425":{"name":"Konjac","note":"Beperkt in geleesnoepjes (verstikkingsgevaar).","detail":{"risks":"Wortelmeel achter Japanse shirataki-noedels. De gel is zo sterk en hittebestendig dat de EU het verbood in mini-gelei-cups na dodelijke verstikkingsincidenten — als verdikkingsmiddel in normale voedingsvormen is het prima.","benefits":"","interestingFact":"","research":""}},"e426":{"name":"Soja-hemicellulose","note":"Sojavezel-emulgator.","detail":{"risks":"Oplosbare vezels geëxtraheerd uit sojapulp, wat voorkomt dat zure melkdranken schiften. Consumenten met een soja-allergie moeten op de bron letten.","benefits":"","interestingFact":"","research":""}},"e432":{"name":"Polysorbaat 20","note":"Synthetische emulgator; microbioomstudies betwist.","detail":{"risks":"De kleinste van de polysorbaat-detergent-emulgatoren. De familie kwam onder een vergrootglas te liggen nadat muizenstudies in 2015 een verdunning van de darmslijmvlieslaag lieten zien; de relevantie voor mensen wordt nog onderzocht.","benefits":"","interestingFact":"","research":""}},"e433":{"name":"Polysorbaat 80","note":"Synthetische emulgator; microbioomstudies betwist.","detail":{"risks":"Een detergentachtige emulgator (consumptie-ijs, sauzen). Een veelgeciteerde studie in Nature uit 2015 vond dat het de beschermende slijmvlieslaag van de darm bij muizen verdunde, wat ontsteking bevorderde — de relevantie voor mensen wordt nog onderzocht, maar het zette emulgatoren op de radar van onderzoekers.","benefits":"","interestingFact":"","research":""}},"e434":{"name":"Polysorbaat 40","note":"Synthetische emulgator; microbioomstudies betwist.","detail":{"risks":"Een polysorbaatemulgator met een middellange keten. Deelt het microbioomdebat van de familie dat geopend werd door de Nature-muizenstudie uit 2015.","benefits":"","interestingFact":"","research":""}},"e435":{"name":"Polysorbaat 60","note":"Synthetische emulgator; onderzoek naar het microbioom ter discussie.","detail":{"risks":"De polysorbaat die het meest wordt gebruikt in gebakscrèmes en slagroomvervangers — het voorkomt dat vetdruppels samensmelten. Net als zijn familieleden is het betrokken bij het darmmicrobioomonderzoek dat werd gestart na de Nature-studie uit 2015.","benefits":"","interestingFact":"","research":""}},"e436":{"name":"Polysorbaat 65","note":"Synthetische emulgator; onderzoek naar het microbioom ter discussie.","detail":{"risks":"De zwaarste polysorbaat, hoofdzakelijk gebruikt in consumptieijs. Zelfde familie, dezelfde openstaande vragen over het microbioom.","benefits":"","interestingFact":"","research":""}},"e440":{"name":"Pectine","note":"Natuurlijk plantaardig geleermiddel.","detail":{"risks":"De natuurlijke gel uit appels en citroenschil — hetgeen dat jam laat opstijven. Het is een oplosbare vezel, en de reden dat oma appelschijfjes toevoegde aan dunne jam.","benefits":"","interestingFact":"","research":""}},"e441":{"name":"Gelatine","note":"Geleermiddel van dierlijke oorsprong.","detail":{"risks":"Collageen uit dierlijke huid en botten, afgebroken tot een eiwit dat smelt op exacte mondtemperatuur — het \\"smelten in de mond\\" van gummyberen is een materiaaleigenschap, geen smaak.","benefits":"","interestingFact":"","research":""}},"e442":{"name":"Ammoniumfosfatiden","note":"Chocolade-emulgator, alternatief voor lecithine.","detail":{"risks":"Een synthetisch neefje van lecithine gemaakt uit koolzaadolie, dat in chocolade hetzelfde werk doet — het vloeibaar houden met minder cacaoboter. Wordt verteerd als gewoon vet plus een spoortje fosfaat.","benefits":"","interestingFact":"","research":""}},"e444":{"name":"Sucrose-acetaatisobutyraat","note":"Troebelheidsstabilisator voor citrusdranken.","detail":{"risks":"Een verzwaard, van suiker afgeleid molecuul dat citrus-aroma-oliën gelijkmatig troebel houdt in frisdrank, in plaats van dat er een ring in de hals van de fles ontstaat.","benefits":"","interestingFact":"","research":""}},"e445":{"name":"Glycerol-esters van houthars","note":"Houdt citrus-oliën gemengd in dranken.","detail":{"risks":"Gezuiverde dennenhars (hetzelfde basismateriaal dat violisten op hun strijkstok wrijven) dat geësterificeerd is om citrus-aroma-oliën in zwevende toestand te houden in sportdranken.","benefits":"","interestingFact":"","research":""}},"e450":{"name":"Difosfaten","note":"Fosfaatadditief; cardiovasculaire discussie bij hoge inneming.","detail":{"risks":"Het rijsmiddel in bakpoeder en de waterbinder in bewerkt vlees en kaas. Afzonderlijk veilig, maar EFSA’s herbeoordeling uit 2019 waarschuwde dat de totale fosfaatinname uit alle bronnen van additieven bij grote consumenten de veilige grenzen kan overschrijden — fosfaten zijn het \\"verborgen zout\\" van ultra-bewerkt voedsel.","benefits":"","interestingFact":"","research":""}},"e451":{"name":"Trifosfaten","note":"Zorgpunt bij fosfaatadditieven.","detail":{"risks":"Fosfaatketens van drie eenheden die gezouten vlees en vis water (en gewicht) laten vasthouden. Ze dragen bij aan de cumulatieve fosfaatbelasting waarvoor EFSA in 2019 waarschuwde.","benefits":"","interestingFact":"","research":""}},"e452":{"name":"Polyfosfaten","note":"Zorgpunt bij fosfaatadditieven.","detail":{"risks":"Lange fosfaatketens — de sterkste waterbinders van de familie, veelvoorkomend in glazuur op diepgevroren zee-vruchten en smeltkaas. Dezelfde waarschuwing voor cumulatieve inname als bij de andere fosfaten.","benefits":"","interestingFact":"","research":""}},"e459":{"name":"Bèta-cyclodextrine","note":"Smaakdrager afkomstig uit zetmeel.","detail":{"risks":"Een ring van glucose-eenheden met een holle kern die aroma-moleculen invangt en langzaam vrijgeeft — moleculaire verpakking gemaakt van zetmeel.","benefits":"","interestingFact":"","research":""}},"e460":{"name":"Cellulose","note":"Plantaardige vezel.","detail":{"risks":"Gezuiverde plantaardige vezel, meestal uit houtpulp — onverteerbare massa die romigheid toevoegt en voorkomt dat geraspte kaas klontert.","benefits":"","interestingFact":"","research":""}},"e461":{"name":"Methylcellulose","note":"Gemodificeerde plantaardige vezel; geleert bij verhitting.","detail":{"risks":"Chemisch gemodificeerde cellulose met een bijzonder kunstje: het geleert bij verhitting en smelt bij afkoeling — het omgekeerde van gelatine. Het is wat plantaardige burgers bij elkaar houdt op de barbecue.","benefits":"","interestingFact":"","research":""}},"e463":{"name":"Hydroxypropylcellulose","note":"Gemodificeerde plantaardige vezel.","detail":{"risks":"Cellulose gemodificeerd voor flexibiliteit, voornamelijk gebruikt als glansmiddel en bindmiddel. Verlaat het lichaam onverteerd, net als elke vezel.","benefits":"","interestingFact":"","research":""}},"e464":{"name":"Hypromellose","note":"Gemodificeerde plantaardige vezel (ook vegetarische capsules).","detail":{"risks":"De gemodificeerde cellulose waar vegetarische medicijncapsules van gemaakt zijn; in voeding verdikt en stabiliseert het. Onverteerbaar en wordt niet opgenomen.","benefits":"","interestingFact":"","research":""}},"e465":{"name":"Ethylmethylcellulose","note":"Gemodificeerde plantaardige vezel.","detail":{"risks":"Een dubbel gemodificeerde cellulose die wordt gebruikt om schuim en emulsies te stabiliseren. Net als de rest van de cellulosefamilie verlaat het het lichaam als vezel.","benefits":"","interestingFact":"","research":""}},"e466":{"name":"Carboxymethylcellulose","note":"Emulgator met ter discussie staande effecten op het darmmicrobioom.","detail":{"risks":"Gemodificeerde cellulose gebruikt in van alles, van consumptieijs tot tandpasta. Kwam samen met polysorbaat 80 voor in de Nature-microbioomstudie uit 2015; een klein menselijk onderzoek uit 2021 liet eveneens verschuivingen in darmbacteriën zien, waardoor het onderwerp van actief onderzoek blijft.","benefits":"","interestingFact":"","research":""}},"e468":{"name":"Gecrosslinkte CMC","note":"Gemodificeerde cellulose.","detail":{"risks":"Carboxymethylcellulose waarvan de ketens aan elkaar zijn gebonden zodat het zwelt in plaats van oplost — voornamelijk een uiteenvallingsmiddel voor tabletten, incidenteel in voeding. Wordt niet opgenomen.","benefits":"","interestingFact":"","research":""}},"e470a":{"name":"Zouten van vetzuren","note":"Zeepachtige zouten van eetbare vetten.","detail":{"risks":"Gewone vetmoleculen gebonden aan natrium, kalium of calcium — technisch gezien zeep, in de praktijk een anti-klonter- en lossingsmiddel dat wordt verteerd als vet.","benefits":"","interestingFact":"","research":""}},"e470b":{"name":"Magnesiumzouten van vetzuren","note":"Anti-klontervetzout.","detail":{"risks":"Magnesiumstearaat, bekend van vrijwel elke pil die ooit is gemaakt — het voorkomt dat poeders aan machines blijven plakken. Wordt verteerd als vet plus een vleugje magnesium.","benefits":"","interestingFact":"","research":""}},"e471":{"name":"Mono- en diglyceriden","note":"Veelgebruikte emulgator; kan transvetten bevatten.","detail":{"risks":"De meest gebruikte emulgator ter wereld — gedeeltelijke vetmoleculen die een brug slaan tussen olie en water, waardoor brood zacht blijft en margarine smeuïg. Chemisch identiek aan normale vetverteringsproducten; het addertje onder het gras is dat industriële productie sporen van transvetten kan achterlaten, die onzichtbaar zijn op het etiket.","benefits":"","interestingFact":"","research":""}},"e472a":{"name":"Azijnzuuresters van glyceriden","note":"Emulgator voor deklagen en opkloppen.","detail":{"risks":"E471-emulgator met azijnzuur gekoppeld — gebruikt in cakedeklagen en spuitbussen met slagroom. Wordt verteerd tot gewoon vet en azijn.","benefits":"","interestingFact":"","research":""}},"e472b":{"name":"Melkzuuresters van glyceriden","note":"Emulgator voor slagroomvervangers.","detail":{"risks":"E471 met melkzuur gekoppeld, dat slagroomvervangers stabiliseert. Valt uiteen in normale vetverteringsproducten plus lactaat.","benefits":"","interestingFact":"","research":""}},"e472c":{"name":"Citroenzuuresters van glyceriden","note":"Emulgator, tevens anti-spatmiddel in vetten.","detail":{"risks":"E471 met citroenzuur gekoppeld; het voorkomt dat margarine spat in de pan. Wordt verteerd tot vet en citraat — beide alledaagse metabolieten.","benefits":"","interestingFact":"","research":""}},"e472e":{"name":"DATEM","note":"Broodemulgator, over het algemeen goed verdragen.","detail":{"risks":"Diacetylwijnsteenzuuresters van mono- en diglyceriden — de glutenversterker van de industriële bakker die supermarktbrood zijn gelijkmatige kruim en volume geeft.","benefits":"","interestingFact":"","research":""}},"e473":{"name":"Sucrose-esters","note":"Emulgator, aanvaardbaar bij typische doseringen.","detail":{"risks":"Suiker gebonden aan vetzuren — een emulgator die mild genoeg is dat verwante verbindingen worden onderzocht als ingrediënten voor babyvoeding. Valt tijdens de spijsvertering weer uiteen in suiker en vet.","benefits":"","interestingFact":"","research":""}},"e475":{"name":"Polyglycerol-esters","note":"Cake-emulgator.","detail":{"risks":"Ketens van glycerol die vetzuren dragen, die lucht in industriële cake kloppen zodat er minder ei nodig is. Wordt verteerd als vet.","benefits":"","interestingFact":"","research":""}},"e476":{"name":"Polyglycerolpolyricinoleaat","note":"Chocolade-emulgator (PGPR); acceptabel voor de EFSA bij typische doseringen.","detail":{"risks":"Gemaakt van ricinusolie, maakt PGPR gesmolten chocolade vloeibaarder, zodat fabrikanten minder dure cacaoboter hoeven te gebruiken. De aanwezigheid ervan is een kostenindicatie, geen gezondheidssignaal — de EFSA vindt het veilig bij doseringen die ver boven een realistische inname liggen.","benefits":"","interestingFact":"","research":""}},"e477":{"name":"Propyleenglycol-esters","note":"Emulgator voor slagroomvervangers.","detail":{"risks":"Vetzuren op een ruggengraat van propyleenglycol, die lucht brengen in slagroomvervangers en cakemixen. Beide helften zijn routinematige metabolieten bij voedingsdoseringen.","benefits":"","interestingFact":"","research":""}},"e479b":{"name":"Thermisch geoxideerde soja-olie-esters","note":"Anti-spatemulgator voor frituurvet.","detail":{"risks":"Soja-olie die opzettelijk warmtebehandeld en geësterificeerd is zodat bakmargarine gelijkmatig bruint in plaats van spat. Beoordeeld door EFSA met een ruime veiligheidsmarge bij normaal gebruik.","benefits":"","interestingFact":"","research":""}},"e481":{"name":"Natriumstearoyllactylaat","note":"Bakkerij-emulgator.","detail":{"risks":"Een hybride van stearinezuur en melkzuur die glutenvliezen versterkt — de reden dat gesneden casinobrood terugveert als je erin knijpt. Wordt verteerd tot alledaags vet en lactaat.","benefits":"","interestingFact":"","research":""}},"e482":{"name":"Calciumstearoyllactylaat","note":"Bakkerij-emulgator.","detail":{"risks":"De calciumtweelingbroer van E481, die hetzelfde deegversterkende werk doet in brood en pannenkoekenmixen.","benefits":"","interestingFact":"","research":""}},"e491":{"name":"Sorbitanmonostearaat","note":"Emulgator, aanvaardbaar bij typische doseringen.","detail":{"risks":"Sorbitol (een suikeralcohol) gebonden aan stearinevet — bijgenaamd \\"synthetische was\\". Het helpt gedroogde gist gelijkmatig te rehydrateren en houdt toppings stabiel; EFSA herbevestigde in 2017 een ruime veiligheidsmarge.","benefits":"","interestingFact":"","research":""}},"e492":{"name":"Sorbitantristearaat","note":"Anti-vetgrijsmiddel voor chocolade.","detail":{"risks":"Een sorbitan-emulgator die de grijze uitslag (\\"vetgrijs\\") op chocolade vertraagt — die cacaoboterkristallen die na verloop van tijd naar het oppervlak migreren. Zelfde familie en veiligheidsbeoordeling als E491.","benefits":"","interestingFact":"","research":""}},"e493":{"name":"Sorbitanmonolauraat","note":"Emulgator.","detail":{"risks":"Het laurinezuurlid van de sorbitanfamilie, gebruikt in toppings en glazuur. Valt tijdens de spijsvertering uiteen in sorbitol en vet.","benefits":"","interestingFact":"","research":""}},"e495":{"name":"Sorbitanmonopalmitaat","note":"Emulgator.","detail":{"risks":"De sorbitaan van palmitinezuur, vooral gebruikt als klophulp. Het spijsverteringsverhaal is hetzelfde als bij zijn E49x-broertjes.","benefits":"","interestingFact":"","research":""}},"e500":{"name":"Natriumcarbonaten","note":"Zuiveringszout.","detail":{"risks":"Zuiveringszout en zijn verwanten — de gasbron in het meeste bakpoeder. Het is ook wat pretzels en ramen-noedels hun kenmerkende alkalische stevige 'bite' geeft.","benefits":"","interestingFact":"","research":""}},"e501":{"name":"Kaliumcarbonaten","note":"Rijsmiddel.","detail":{"risks":"Het kaliumneefje van zuiveringszout — historisch gezien \\"parelas\\", geloogd uit houtas, en het rijsmiddel in ontbijtkoek van vóór de uitvinding van bakpoeder.","benefits":"","interestingFact":"","research":""}},"e503":{"name":"Ammoniumcarbonaten","note":"Traditioneel rijsmiddel.","detail":{"risks":"\\"Bakkersammonia\\", het rijsmiddel uit oude Europese koekjesrecepten van vóór het bakpoedertijdperk. Het ruikt in de oven scherp naar ammoniak, maar elk spoor bakt eruit en laat extra knapperige koekjes achter.","benefits":"","interestingFact":"","research":""}},"e504":{"name":"Magnesiumcarbonaten","note":"Antiklontermiddel (ook klimkrijt).","detail":{"risks":"Het witte poeder waar turners en klimmers hun handen mee insmeren; het houdt keukenzout strooibaar. Maagzuur verandert het in gewoon opgelost magnesium.","benefits":"","interestingFact":"","research":""}},"e507":{"name":"Zoutzuur","note":"Proceszuur, geneutraliseerd in het product.","detail":{"risks":"Klinkt alarmerend, maar je maag produceert elke dag hetzelfde zuur in een hogere concentratie. In de voedingsmiddelenverwerking wordt het geneutraliseerd voordat het product af is.","benefits":"","interestingFact":"","research":""}},"e508":{"name":"Kaliumchloride","note":"Zoutvervangend mineraal.","detail":{"risks":"De standaard natriumarme zoutvervanger — kalium in plaats van natrium, met een licht metaalachtige bijsmaak. Voor de meeste mensen is dat extra kalium een pluspunt.","benefits":"","interestingFact":"","research":""}},"e509":{"name":"Calciumchloride","note":"Stevigheidsmiddel (groenten in blik, kaasmaken).","detail":{"risks":"Een calciumzout dat plantaardige pectines bindt, waardoor tomaten in blik en augurken stevig blijven. Kaasmakers voegen het toe aan melk om de stremming te helpen. Ook de \\"vloeistof\\" in veel strooizouten — concentratie is alles.","benefits":"","interestingFact":"","research":""}},"e511":{"name":"Magnesiumchloride","note":"Stevigheidsmiddel (ook tofu-stremmiddel nigari).","detail":{"risks":"Magnesium uit zeewater — als \\"nigari\\" het traditionele Japanse tofu-stremmiddel dat sojamelk laat stremmen tot wringel. Een bron van magnesium in de voeding.","benefits":"","interestingFact":"","research":""}},"e513":{"name":"Zwavelzuur","note":"Proceszuur, geneutraliseerd in het product.","detail":{"risks":"Alleen gebruikt tijdens het verwerkingsproces (bijvoorbeeld om de zuurgraad van brouwwater aan te passen) en volledig geneutraliseerd tot sulfaatzouten voordat het product in het schap belandt.","benefits":"","interestingFact":"","research":""}},"e514":{"name":"Natriumsulfaten","note":"Zuurteregelaar.","detail":{"risks":"Een neutraal mineraalzout — voor 18e-eeuwse apothekers Glauberzout, die het voorschreven als laxeermiddel, wat het in grote hoeveelheden nog steeds is.","benefits":"","interestingFact":"","research":""}},"e516":{"name":"Calciumsulfaat","note":"Gips — tofu-stremmiddel, meelverbeteraar.","detail":{"risks":"Gips van levensmiddelenkwaliteit (het gezuiverde mineraal uit gipsplaten). Het is het klassieke Chinese tofu-stremmiddel en een gistvoedingsstof bij het bakken, dat onderweg bruikbare calcium levert.","benefits":"","interestingFact":"","research":""}},"e524":{"name":"Natriumhydroxide","note":"Loog — proceshulpstof, volledig reageerd in het product.","detail":{"risks":"Bijtend in de fles, onschadelijk op het bord: pretzels danken hun mahoniehouten korst aan een loogbadje, dat door het bakken volledig wordt geneutraliseerd.","benefits":"","interestingFact":"","research":""}},"e526":{"name":"Calciumhydroxide","note":"Gebluste kalk, proceshulpstof.","detail":{"risks":"Gebluste kalk — de \\"cal\\" van de Mexicaanse nixtamalisatie, die al 3.500 jaar mais verzacht voor tortilla's en de niacin erin vrijmaakt. Volledig reageerd in het eindproduct.","benefits":"","interestingFact":"","research":""}},"e527":{"name":"Ammoniumhydroxide","note":"Procesalkali.","detail":{"risks":"Een ammoniakoplossing die wordt gebruikt om de zuurgraad tijdens het verwerken (met name van cacao) aan te passen. Het reageert weg of verdampt; het ammonium dat overblijft, neemt deel aan de normale stikstofstofwisseling.","benefits":"","interestingFact":"","research":""}},"e529":{"name":"Calciumoxide","note":"Ongebluste kalk, proceshulpstof.","detail":{"risks":"Ongebluste kalk — het blust tot calciumhydroxide zodra het in aanraking komt met vocht, doet hetzelfde werk als E526 en eindigt als gewoon calcium.","benefits":"","interestingFact":"","research":""}},"e530":{"name":"Magnesiumoxide","note":"Antiklontermineraal.","detail":{"risks":"Hetzelfde magnesiumoxide dat verkocht wordt als supplement en maagzuurbinder, en dat hier cacaopoeder goed strooibaar houdt.","benefits":"","interestingFact":"","research":""}},"e535":{"name":"Natriumferrocyanide","note":"Antiklontermiddel in zout.","detail":{"risks":"Ondanks de enge naam zit het cyanide zo stevig aan ijzer gebonden dat het onopgenomen het lichaam verlaat — het is wat keukenzout strooibaar houdt bij vochtig weer.","benefits":"","interestingFact":"","research":""}},"e536":{"name":"Kaliumferrocyanide","note":"Antiklontermiddel in zout.","detail":{"risks":"De kaliumvorm van E535, met dezelfde ijzergebonden chemie: de cyanidegroep kan in het lichaam niet vrijkomen, en de EFSA heeft de veiligheid in 2018 opnieuw bevestigd.","benefits":"","interestingFact":"","research":""}},"e538":{"name":"Calciumferrocyanide","note":"Antiklontermiddel in zout.","detail":{"risks":"De zeldzaamste van de drie ferrocyanide-antiklonterzouten, met identieke gebonden chemie en dezelfde beoordeling door de EFSA.","benefits":"","interestingFact":"","research":""}},"e541":{"name":"Natriumaluminiumfosfaat","note":"Rijsmiddel op basis van aluminium.","detail":{"risks":"Een traagwerkend bakzuur waarvan het aluminium bijdraagt aan de totale inname via de voeding — EFSA heeft de regels voor aluminiumadditieven in 2012 verstrakt, waardoor het grotendeels uit EU-recepten is verdwenen.","benefits":"","interestingFact":"","research":""}},"e551":{"name":"Siliciumdioxide","note":"Antiklontermiddel; gehalte aan nanodeeltjes wordt herzien door de EU.","detail":{"risks":"Gezuiverd zand, in een poedervorm die zo fijn is dat het deeltjes omhult en kruidenmixen en oplossoepen strooibaar houdt. Chemisch inert; de open vraag waar EFSA achteraan zit, is of de fractie op nanoformaat zich kan ophopen.","benefits":"","interestingFact":"","research":""}},"e552":{"name":"Calciumsilicaat","note":"Antiklontermineraal.","detail":{"risks":"Een krijt-silicamineraal dat vele malen zijn eigen gewicht aan vocht opneemt, waardoor poeders los blijven. Wordt vrijwel niet opgenomen.","benefits":"","interestingFact":"","research":""}},"e553b":{"name":"Talk","note":"Antiklontermineraal (levensmiddelenkwaliteit, asbestvrij).","detail":{"risks":"Het zachtste mineraal op aarde, dat rijstkorrels gepolijst maakt en kauwgom van een poederlaagje voorziet. Van levensmiddelenkwaliteit is het gegarandeerd asbestvrij; het verlaat het lichaam onverteerd.","benefits":"","interestingFact":"","research":""}},"e554":{"name":"Natriumaluminosilicaat","note":"Antiklontermiddel op basis van aluminium.","detail":{"risks":"Een antiklonterklei waarvan het aluminiumgehalte meetelt voor EFSA’s strenge wekelijkse aluminiumlimiet — de reden waarom EU-regelgevers deze groep in 2014 hebben ingeperkt.","benefits":"","interestingFact":"","research":""}},"e555":{"name":"Kaliumaluminosilicaat","note":"Draagstof op basis van aluminium (parelmoerkleuren).","detail":{"risks":"Natuurlijk mica — de glans op parelmoerachtige taartdecoraties. Aangemerkt om dezelfde reden van aluminiumophoping als zijn broertjes.","benefits":"","interestingFact":"","research":""}},"e558":{"name":"Bentoniet","note":"Klei gebruikt voor het klaren van wijn en sap.","detail":{"risks":"Een vulkanische klei die opzwelt in water en vertroebelende eiwitten bindt — de meeste witte wijn die je hebt gedronken is hiermee geklaard en vervolgens gefilterd.","benefits":"","interestingFact":"","research":""}},"e559":{"name":"Kaolien","note":"Klei-antiklontermiddel.","detail":{"risks":"Porseleinaarde — het porseleinmineraal — dat af en toe wordt gebruikt als antiklontermiddel. Inert en onopgenomen.","benefits":"","interestingFact":"","research":""}},"e570":{"name":"Vetzuren","note":"Gewone eetbare vetzuren.","detail":{"risks":"Stearinezuur en soortgenoten — dezelfde vetzuren die je lichaam uit elk vet haalt, gebruikt als glans- en antiklontermiddelen.","benefits":"","interestingFact":"","research":""}},"e575":{"name":"Glucono-delta-lacton","note":"Zuur met geleidelijke afgifte (tofu, gepekeld vlees).","detail":{"risks":"Een geoxideerde suiker die in water langzaam zuur wordt — perfect voor zijdetofu, waar de geleidelijke pH-daling sojamelk laat stremmen tot een gladde gel.","benefits":"","interestingFact":"","research":""}},"e576":{"name":"Natriumgluconaat","note":"Mineraalzout van gluconzuur.","detail":{"risks":"Glucose geoxideerd en gebonden aan natrium — een mineraaldrager en stabilisator die net als suiker wordt verwerkt.","benefits":"","interestingFact":"","research":""}},"e577":{"name":"Kaliumgluconaat","note":"Mineraalzout van gluconzuur.","detail":{"risks":"De kaliumvorm van gluconaat, zacht genoeg dat apotheken het als kaliumsupplement verkopen.","benefits":"","interestingFact":"","research":""}},"e578":{"name":"Calciumgluconaat","note":"Calciumzout, stevigheidsmiddel.","detail":{"risks":"Calcium op een suikerzuurdrager — dezelfde verbinding die ziekenhuizen intraveneus toedienen bij een calciumtekort. In voeding maakt het groente en fruit steviger.","benefits":"","interestingFact":"","research":""}},"e579":{"name":"Ferrogluconaat","note":"IJzerzout — kleurt olijven zwart.","detail":{"risks":"Een ijzersupplement dat als kleurstof dient: \\"zwarte\\" olijven in blik zijn meestal groene olijven die zwart geoxideerd zijn en met dit ijzerzout zijn gefixeerd.","benefits":"","interestingFact":"","research":""}},"e585":{"name":"Ferrolactaat","note":"IJzerzout, olijfverdonkeraar.","detail":{"risks":"IJzer gebonden aan lactaat, dat hetzelfde werk doet bij het verdonkeren van olijven als E579, en gebruikt wordt om voedingsmiddelen met ijzer te verrijken.","benefits":"","interestingFact":"","research":""}},"e586":{"name":"4-Hexylresorcinol","note":"Antiverbruiningsmiddel voor garnalen.","detail":{"risks":"Voorkomt dat de schaal van garnalen na de vangst zwarte vlekken ontwikkelt door hetzelfde enzym te blokkeren dat opgesneden appels bruin kleurt. Wordt ook gebruikt als antiseptisch middel in keeltabletten.","benefits":"","interestingFact":"","research":""}},"e620":{"name":"Glutaminezuur","note":"Umamiversterker; overgevoeligheidsreacties bij sommige mensen.","detail":{"risks":"De vrije vorm van het meest overvloedige aminozuur in je voeding — Parmezaanse kaas bestaat voor 1,2% uit zuiver glutamaat. Als additief concentreert het umami; de discussies over overgevoeligheid en overeten komen overeen met die over MSG (E621).","benefits":"","interestingFact":"","research":""}},"e621":{"name":"Mononatriumglutamaat","note":"Smaakversterker; overgevoeligheidsreacties bij sommige mensen.","detail":{"risks":"De zuivere vorm van umami, in 1908 ontdekt in de bouillon van kombu-zeewier. Glutamaat zelf zit in Parmezaanse kaas, tomaten en moedermelk; de paniek rond het \\"Chinees-restaurantsyndroom\\" uit 1968 hield grotendeels geen stand in gecontroleerde testen, al reageert een klein deel van de mensen wel op hoge doses. EFSA stelde in 2017 een formele innamelimiet vast — die vooral overschreden wordt door een dieet met veel snacks. Het echte nutritionele probleem: het maakt ultra-verwerkt voedsel erg makkelijk om van te overeten.","benefits":"","interestingFact":"","research":""}},"e622":{"name":"Monokaliumglutamaat","note":"Glutamaat-smaakversterker.","detail":{"risks":"MSG waarbij kalium de plaats van natrium inneemt, gebruikt in natriumarme recepten. Identiek umami-mechanisme en dezelfde EFSA-innamelimiet voor glutamaat.","benefits":"","interestingFact":"","research":""}},"e627":{"name":"Dinatriumguanylaat","note":"Smaakversterker, vaak gecombineerd met MSG.","detail":{"risks":"Een nucleotide die umami vermenigvuldigt — in combinatie met MSG smaakt het tot 30× sterker dan elk afzonderlijk, wat verklaart waarom ze samen op etiketten staan. Gewonnen uit gist of vis; mensen met jicht wordt geadviseerd om purinerijke additieven zoals deze te beperken.","benefits":"","interestingFact":"","research":""}},"e628":{"name":"Dikaliumguanylaat","note":"Nucleotide-smaakversterker.","detail":{"risks":"De kaliumvorm van guanylaat (E627), die umami versterkt in natriumarme producten. Dezelfde gistoorsprong en purinewaarschuwing voor mensen die gevoelig zijn voor jicht.","benefits":"","interestingFact":"","research":""}},"e631":{"name":"Dinaatriuminosinaat","note":"Smaakversterker, vaak gecombineerd met MSG.","detail":{"risks":"De umami-nucleotide uit gedroogde bonitovlokken (de basis van Japanse dashi), tegenwoordig gemaakt via fermentatie. Dezelfde MSG-synergie en purineopmerkingen als E627.","benefits":"","interestingFact":"","research":""}},"e635":{"name":"Dinatriumribonucleotiden","note":"Combinatie van E627 + E631; umami-booster.","detail":{"risks":"Een 50/50-menging van guanylaat en inosinaat — één regel op het etiket die beide umami-nucleotiden levert. De aanwezigheid ervan wijst vrijwel altijd op MSG (of een glutamaatrijk extract) in de buurt, aangezien het alleen weinig doet.","benefits":"","interestingFact":"","research":""}},"e640":{"name":"Glycine","note":"Het eenvoudigste aminozuur, lichtzoet.","detail":{"risks":"Het kleinste aminozuur — een derde van het eiwit collageen bestaat uit glycine. Als additief rondt het bittere randjes af en voegt het een lichte zoetheid toe.","benefits":"","interestingFact":"","research":""}},"e650":{"name":"Zinkacetaat","note":"Zinkzout (kauwgom).","detail":{"risks":"Zink gebonden aan azijnzuur, voornamelijk gebruikt in ademverfrissende kauwgom waar zink zwavelverbindingen neutraliseert. Hetzelfde zout wordt gebruikt in zuigtabletten tegen verkoudheid.","benefits":"","interestingFact":"","research":""}},"e900":{"name":"Dimethylpolysiloxaan","note":"Siliconen anti-schuimmiddel (frituurolie).","detail":{"risks":"Een siliconen voor levensmiddelen die voorkomt dat frituurolie overschuimt — de reden waarom de friteuses in fastfoodrestaurants niet overkoken. Volledig inert en wordt niet opgenomen; ook het hoofdbestanddeel van Silly Putty.","benefits":"","interestingFact":"","research":""}},"e901":{"name":"Bijenwas","note":"Natuurlijke glanswas.","detail":{"risks":"Dezelfde was waar bijen hun raat mee bouwen, opgepoetst op snoepjes en citrusvruchten voor glans. Onverteerbaar — het passeert er direct doorheen.","benefits":"","interestingFact":"","research":""}},"e902":{"name":"Candelillawas","note":"Plantaardige glanswas.","detail":{"risks":"Was afgeschraapt van een Mexicaanse woestijnstruik die zichzelf beschermt tegen droogte — nu bedekt het in plaats daarvan je gummiberen. Onverteerbaar en inert.","benefits":"","interestingFact":"","research":""}},"e903":{"name":"Carnaubawas","note":"Palmblad-glanswas.","detail":{"risks":"Afkomstig van Braziliaanse palmbladeren — de hardste natuurlijke was die bekend is, die zowel M&M's als sportwagens laat glimmen.","benefits":"","interestingFact":"","research":""}},"e904":{"name":"Shellak","note":"Glansmiddel uit insectenhars.","detail":{"risks":"Afgescheiden door de lakschildluis op Thaise en Indiase bomen en vervolgens gezuiverd — het glimmende laagje op chocoladeflikken en appels, en dezelfde hars als in gepolitoerde meubels. Niet vegetarisch.","benefits":"","interestingFact":"","research":""}},"e905":{"name":"Microkristallijne was","note":"Glanswas uit aardolie.","detail":{"risks":"Een zeer geraffineerde aardoliewas die kauwgom en snoep laat glanzen. Te groot om te worden opgenomen, dus het passeert het lichaam — de enige eis van EFSA is zuiverheidscontrole.","benefits":"","interestingFact":"","research":""}},"e914":{"name":"Geoxideerde polyethyleenwas","note":"Synthetische was voor citrusfruit.","detail":{"risks":"Een synthetische was die op de schil van citrusvruchten wordt gespoten om vochtverlies te vertragen op weg van de boomgaard naar het schap. Blijft op de schil zitten; was het fruit voordat je de schil raspt.","benefits":"","interestingFact":"","research":""}},"e920":{"name":"L-Cysteïne","note":"Deegverbeteraar uit fermentatie.","detail":{"risks":"Een aminozuur dat gluten versoepelt, zodat industriële deegmachines het snel kunnen uitrekken. Historisch gezien gewonnen uit veren en menselijk haar (verboden bronnen in de EU sinds 2001 — tegenwoordig wordt het gefermenteerd uit suiker), een feit dat de reputatie ervan spraakmakend houdt.","benefits":"","interestingFact":"","research":""}},"e927b":{"name":"Carbamide","note":"Textuurverbeteraar voor kauwgom.","detail":{"risks":"Ureum — een molecuul dat je lichaam voortdurend aanmaakt bij het eiwitmetabolisme — maakt suikervrije kauwgom zachter. Onbeduidend bij de doseringen van enkele milligrammen waar het om gaat.","benefits":"","interestingFact":"","research":""}},"e938":{"name":"Argon","note":"Inert verpakkingsgas.","detail":{"risks":"Een edelgas uit de lucht (1% van elke ademteug) dat nergens mee reageert — in verpakkingen gespoten om zuurstof te verdrijven.","benefits":"","interestingFact":"","research":""}},"e939":{"name":"Helium","note":"Inert verpakkingsgas.","detail":{"risks":"Het ballongas, volledig inert, dat af en toe wordt gebruikt om voedsel in te verpakken. Het ontsnapt op het moment dat je de verpakking opent.","benefits":"","interestingFact":"","research":""}},"e941":{"name":"Stikstof","note":"Verpakkingsgas — 78% van de lucht die je inademt.","detail":{"risks":"Het gas dat de \\"lege\\" ruimte in zakken chips vult is geen doorgestoken kaart — het is stikstof dat de chips beschermt tegen zuurstof en fijncruisen. Ook hetgeen dat nitro-koffie romig maakt.","benefits":"","interestingFact":"","research":""}},"e942":{"name":"Dinitrogeenoxide","note":"Drijfgas voor slagroom (lachgas).","detail":{"risks":"Het drijfgas in slagroompatronen. Het lost onder druk op in de room en zet bij het vrijkomen achtvoudig uit — het spoor dat je binnenkrijgt is binnen enkele minuten verdwenen.","benefits":"","interestingFact":"","research":""}},"e948":{"name":"Zuurstof","note":"Verpakkingsgas.","detail":{"risks":"Gewone zuurstof, soms toegevoegd aan verpakkingen rood vlees om het oppervlak helderrood te houden. Met elke ademteug adem je veel meer in.","benefits":"","interestingFact":"","research":""}},"e949":{"name":"Waterstof","note":"Verpakkingsgas.","detail":{"risks":"Het lichtste gas, zelden gebruikt als verpakkingsgas. Inert in voedsel en lang verdwenen tegen de tijd dat je het eet.","benefits":"","interestingFact":"","research":""}},"e999":{"name":"Quillaia-extract","note":"Schuimmiddel uit zeepboomschors (schuim van root beer).","detail":{"risks":"Extract van de Chileense zeepboom, wiens natuurlijke saponinen de schuimlaag van root beer maken. Hetzelfde extract wordt gebruikt als adjuvant in vaccins — in voedseldoseringen maakt het gewoon bubbels.","benefits":"","interestingFact":"","research":""}},"e950":{"name":"Acesulfaam-K","note":"Kunstmatige zoetstof; langetermijneffecten ter discussie.","detail":{"risks":"200× zoeter dan suiker, nul calorieën, wordt helemaal niet gemetaboliseerd — het verlaat je lichaam binnen 24 uur onveranderd. Langetermijn-epidemiologie (waaronder het advies van de WHO uit 2023 tegen zoetstoffen voor gewichtsbeheersing) houdt de discussie open.","benefits":"","interestingFact":"","research":""}},"e951":{"name":"Aspartaam","note":"IARC klasse 2B (mogelijk kankerverwekkend, 2023); innamelimieten van toepassing.","detail":{"risks":"Twee aan elkaar gekoppelde aminozuren, 200× zoeter dan suiker. In 2023 classificeerde het IARC het als \\"mogelijk kankerverwekkend\\" (dezelfde 2B-categorie als aloë vera en ingelegde groenten), terwijl het additievencomité van de WHO de innamelimiet handhaafde — ongeveer 12 blikjes light-frisdrank per dag voor een volwassene. Mensen met de genetische aandoening PKU moeten het volledig vermijden; daarvoor dient de waarschuwing \\"bevat een bron van fenylalanine\\".","benefits":"","interestingFact":"","research":""}},"e952":{"name":"Cyclamaten","note":"Zoetstof verboden in de VS, beperkte doseringen in de EU.","detail":{"risks":"Ontdekt in 1937 door een student die zijn sigaret op laboratoriumpoeder legde en een zoete smaak proefde. Sinds 1970 verboden in de VS vanwege (later betwiste) bevindingen over tumoren bij ratten; de EU staat het toe met strenge limieten.","benefits":"","interestingFact":"","research":""}},"e953":{"name":"Isomalt","note":"Polyol; laxerend bij hoge doses.","detail":{"risks":"De favoriet van de suikerkunstenaar — het smelt glashelder zonder te karamelliseren, dus spektakelstukken in tv-bakprogramma's zijn meestal van isomalt. De standaard spijsverteringswaarschuwingen voor polyolen zijn van toepassing.","benefits":"","interestingFact":"","research":""}},"e954":{"name":"Sacharine","note":"Kunstmatige zoetstof met een bewogen geschiedenis.","detail":{"risks":"De oudste kunstmatige zoetstof (1879, ontdekt door een scheikundige die zijn handen niet wasste voor het eten). Droeg 20 jaar lang een kankerwaarschuwing in de VS totdat werd aangetoond dat het blaastumormechanisme bij ratten niet geldt voor mensen — van de lijst geschrapt in 2000, maar de lange schaduw blijft.","benefits":"","interestingFact":"","research":""}},"e955":{"name":"Sucralose","note":"Kunstmatige zoetstof; discussies over verhitting en microbioom.","detail":{"risks":"Suiker waarin drie chlooratomen zijn vervangen — 600× zoeter en grotendeels niet-opgenomen. Huidige discussies: het kan bij hoge baktemperaturen afbreken tot twijfelachtige verbindingen, en onderzoeken spreken elkaar tegen over de effecten op het darmmicrobioom.","benefits":"","interestingFact":"","research":""}},"e957":{"name":"Thaumatine","note":"Zoet eiwit uit een Afrikaanse vrucht.","detail":{"risks":"Een eiwit uit de West-Afrikaanse katemfe-vrucht — de zoetste bekende natuurlijke stof, naar gewicht ongeveer 2.000× zoeter dan suiker. Wordt net als elk ander eiwit verteerd.","benefits":"","interestingFact":"","research":""}},"e959":{"name":"Neohesperidine-DC","note":"Zoetstof afkomstig van citrusvruchten.","detail":{"risks":"Gemaakt van verbindingen uit de schil van zure sinaasappels, 1.500× zoeter dan suiker met een mentholachtige nasmaak; wordt ook gebruikt om bitterheid in geneesmiddelen te maskeren.","benefits":"","interestingFact":"","research":""}},"e960":{"name":"Steviolglycosiden","note":"Zoetstof uit stevia.","detail":{"risks":"Geëxtraheerd uit steviabladen, al eeuwenlang gebruikt door het Guaraní-volk in Paraguay. 250–300× zoeter dan suiker met nul calorieën; je darmbacteriën breken het af en het wordt uitgescheiden. De lichte dropachtige nasmaak is het compromis.","benefits":"","interestingFact":"","research":""}},"e961":{"name":"Neotaam","note":"Aspartaamderivaat, 8000× zoeter dan suiker.","detail":{"risks":"Aspartaam dat zodanig is herontworpen dat het ~40× sterker is en stabiel blijft tijdens het bakken. De doseringen zijn microscopisch klein, en anders dan bij aspartaam komt er zo weinig fenylalanine bij vrij dat een PKU-waarschuwing niet nodig is; langetermijngegevens zijn simpelweg schaarser.","benefits":"","interestingFact":"","research":""}},"e962":{"name":"Aspartaam-acesulfaamzout","note":"Gecombineerde zoetstof; zie opmerkingen over aspartaam.","detail":{"risks":"Aspartaam en acesulfaam-K gekristalliseerd tot één molecuul dat in je mond weer uiteenvalt in beide stoffen — alle overwegingen voor beide zijn van toepassing, inclusief de PKU-waarschuwing.","benefits":"","interestingFact":"","research":""}},"e965":{"name":"Maltitol","note":"Polyol; laxerend bij hoge doseringen.","detail":{"risks":"De standaard suikervervanger in chocolade \\"zonder toegevoegde suikers\\" — 90% zo zoet als suiker met de helft van de calorieën. Tevens de meest beruchte polyol voor spijsverteringsongemakken boven ~20 g, vandaar de waarschuwingen op suikervrij snoepgoed.","benefits":"","interestingFact":"","research":""}},"e966":{"name":"Lactitol","note":"Polyol uit melk; laxerend bij hoge doseringen.","detail":{"risks":"Een suikeralcohol gemaakt uit melksuiker, lichtzoet en voornamelijk gefermenteerd door darmbacteriën — in farmaceutische doseringen wordt exact hetzelfde molecuul letterlijk verkocht als laxeermiddel.","benefits":"","interestingFact":"","research":""}},"e967":{"name":"Xylitol","note":"Polyol; laxerend bij hoge doseringen.","detail":{"risks":"Suikeralcohol uit berkenschors die mondbacteriën niet kunnen fermenteren — het kauwen van xylitolkauwgom vermindert aantoonbaar gaatjes, een zeldzaam additief met een bewezen nut. Twee waarschuwingen: laxerend boven ~30 g en extreem giftig voor honden.","benefits":"","interestingFact":"","research":""}},"e968":{"name":"Erythritol","note":"Polyol; studie uit 2023 ontketende een cardiovasculair debat.","detail":{"risks":"De zachtste polyol — 90% wordt al opgenomen voordat het de dikke darm bereikt, dus vrijwel geen spijsverteringseffecten, en nul calorieën. Een studie in Nature Medicine uit 2023 bracht een hoge erythritolspiegel in het bloed in verband met een risico op stolling; of erythritol uit voeding daar de oorzaak van is, wordt momenteel actief onderzocht.","benefits":"","interestingFact":"","research":""}},"e1103":{"name":"Invertase","note":"Enzym dat de vulling van snoep vloeibaar maakt.","detail":{"risks":"Het enzym (uit gist) dat stevige fondant in enkele weken tijd vloeibaar maakt — zo krijgen kersen in chocolade hun vloeibare vulling nadat ze zijn gevuld met een vaste pasta.","benefits":"","interestingFact":"","research":""}},"e1105":{"name":"Lysozym","note":"Eiwitenzym als conserveermiddel (kaas, wijn).","detail":{"risks":"Een antibacterieel enzym uit kippeneiwit — hetzelfde enzym dat in je tranen en speeksel zit. Consumenten met een ei-allergie moeten weten dat het verstopt zit in sommige harde kazen en wijnen.","benefits":"","interestingFact":"","research":""}},"e1200":{"name":"Polydextrose","note":"Synthetische oplosbare vezel.","detail":{"risks":"Glucose aan elkaar gebonden in patronen die je enzymen niet kunnen knippen, waardoor het zich gedraagt als oplosbare vezel — het geeft volume aan \\"light\\"-producten met 1 kcal/g in plaats van de 4 van suiker.","benefits":"","interestingFact":"","research":""}},"e1201":{"name":"Polyvinylpyrrolidon","note":"Klarmiddel en tabletbindmiddel.","detail":{"risks":"Een polymer dat de polyfenolen bindt die bier en sap troebel zouden maken, en er vervolgens samen mee wordt uitgefilterd. Eventuele achtergebleven sporen verlaten het lichaam onopgenomen.","benefits":"","interestingFact":"","research":""}},"e1400":{"name":"Dextrines","note":"Verdikker op basis van geroosterd zetmeel.","detail":{"risks":"Zetmeel dat licht is afgebroken door roosteren — dezelfde chemie die de korst van een baguette bruin maakt. Wordt precies zo verteerd als zetmeel.","benefits":"","interestingFact":"","research":""}},"e1404":{"name":"Geoxideerd zetmeel","note":"Gemodificeerd zetmeel; wordt verteerd als zetmeel.","detail":{"risks":"Zetmeel dat zo is behandeld dat het verdikt bij een lagere viscositeit voor crèmes en beslag. \\"Gemodificeerd\\" betekent fysiek/chemisch aangepast — niet genetisch gemodificeerd — en het wordt verteerd als gewoon zetmeel.","benefits":"","interestingFact":"","research":""}},"e1410":{"name":"Monozetmeelfosfaat","note":"Gemodificeerd zetmeel; wordt verteerd als zetmeel.","detail":{"risks":"Zetmeel met fosfaatankers die bestand zijn tegen hitte en zuren, zodat sauzen in blik dik blijven. Wordt verteerd als zetmeel.","benefits":"","interestingFact":"","research":""}},"e1412":{"name":"Dizetmeelfosfaat","note":"Gemodificeerd zetmeel; wordt verteerd als zetmeel.","detail":{"risks":"Zetmeel dat gecrosslinkt is met fosfaatbruggen om roeren en hitte te weerstaan — de basis van instantpudding. Wordt verteerd als zetmeel.","benefits":"","interestingFact":"","research":""}},"e1414":{"name":"Geacetyleerd dizetmeelfosfaat","note":"Gemodificeerd zetmeel; wordt verteerd als zetmeel.","detail":{"risks":"Gecrosslinkt zetmeel waaraan acetylgroepen zijn toegevoegd voor vries-dooistabiliteit — de reden waarom ingevroren kant-en-klaarmaaltijden geen vocht verliezen bij het opwarmen. Wordt verteerd als zetmeel.","benefits":"","interestingFact":"","research":""}},"e1420":{"name":"Geacetyleerd zetmeel","note":"Gemodificeerd zetmeel; wordt verteerd als zetmeel.","detail":{"risks":"Zetmeel met van azijn afgeleide acetylgroepen, wat retrogradatie (het oud worden van zetmeel) tegengaat. Wordt verteerd als zetmeel.","benefits":"","interestingFact":"","research":""}},"e1422":{"name":"Geacetyleerd dizetmeeladipaat","note":"Gemodificeerd zetmeel; wordt verteerd als zetmeel.","detail":{"risks":"\\"Gemodificeerd zetmeel\\" betekent niet genetisch gemodificeerd — het is maïs- of aardappelzetmeel dat chemisch is aangepast zodat sauzen invriezen en opwarmen overleven zonder waterig te worden. Je lichaam verteert het als gewoon zetmeel.","benefits":"","interestingFact":"","research":""}},"e1440":{"name":"Hydroxypropylzetmeel","note":"Gemodificeerd zetmeel, over het algemeen goed verdragen.","detail":{"risks":"Zetmeel voorzien van wateraantrekkende zijgroepen voor een gladde verdikking bij lage temperaturen. Grotendeels verteerd als zetmeel; de gemodificeerde fractie verlaat het lichaam als vezel.","benefits":"","interestingFact":"","research":""}},"e1442":{"name":"Hydroxypropyldizetmeelfosfaat","note":"Gemodificeerd zetmeel, over het algemeen goed verdragen.","detail":{"risks":"De meest robuuste van de gemodificeerde zetmelen — gecrosslinkt en gesubstitueerd, behoudt zijn verdikkende werking bij inblikken, invriezen en opwarmen. Grotendeels verteerd als zetmeel.","benefits":"","interestingFact":"","research":""}},"e1450":{"name":"Zetmeelnatriumoctenylsuccinaat","note":"Emulgator op basis van zetmeel (ook in vitamines).","detail":{"risks":"Zetmeel voorzien van een vetaantrekkende staart zodat het kan emulgeren — de drager die poederaroma's en vitamines in zuigelingenvoeding gelijkmatig verdeeld houdt.","benefits":"","interestingFact":"","research":""}},"e1451":{"name":"Geacetyleerd geoxideerd zetmeel","note":"Gemodificeerd zetmeel; wordt verteerd als zetmeel.","detail":{"risks":"Een dubbel behandeld zetmeel dat de helderheid van oxidatie combineert met de stabiliteit van acetyl. Qua spijsvertering blijft het echter gewoon zetmeel.","benefits":"","interestingFact":"","research":""}},"e1505":{"name":"Triethylcitraat","note":"Citraat-aromadrager en schuimstabilisator.","detail":{"risks":"Citroenzuur met drie ethanolgroepen — het stabiliseert opgeklopt eiwit in vloeibaar ei-product in pak en draagt aroma's. Wordt tijdens de spijsvertering weer gesplitst in citraat en sporen van alcohol.","benefits":"","interestingFact":"","research":""}},"e1518":{"name":"Triacetine","note":"Aromadrager op basis van glycerol.","detail":{"risks":"Glycerol met drie azijnzuurgroepen, die aroma's oplost in kauwgom en snoep. Wordt verteerd tot glycerol en acetaat, beide alledaagse metabolieten.","benefits":"","interestingFact":"","research":""}},"e1520":{"name":"Propyleenglycol","note":"Aromadrager; veilig bij voedingsdoseringen.","detail":{"risks":"Het oplosmiddel dat de meeste vloeibare voedingsaroma's draagt. Wordt gemetaboliseerd tot melkzuur; de limiet van de EFSA is ruim vergeleken met de blootstelling via voeding. De slechte reputatie komt vooral doordat het ook wordt gebruikt in e-sigaretten en antivriesmiddelen — bij voedingsdoseringen is het onbeduidend.","benefits":"","interestingFact":"","research":""}}}`),n={methylparaben:{note:`Korte-ketenparabeen; SCCS vindt het veilig bij ≤0.4%, maar het is een gedocumenteerde zwakke hormoonnabootser.`},ethylparaben:{note:`Korte-ketenparabeen; toegestaan in de EU met concentratielimieten.`},propylparaben:{note:`Lange-ketenparabeen met sterkere aanwijzingen voor hormoonverstorende activiteit; in de EU beperkt qua concentratie.`},butylparaben:{note:`Lange-ketenparabeen met de sterkste aanwijzingen voor hormoonverstorende activiteit; beperkt in de EU.`},isobutylparaben:{note:`Sinds 2014 verboden in EU-cosmetica.`},paraben:{note:`Conserveermiddel uit de parabenenfamilie; het debat over hormoonverstorende activiteit varieert per ketenlengte.`},formaldehyde:{note:`IARC Groep 1-carcinogeen; verboden of streng beperkt in EU-cosmetica.`},"dmdm hydantoin":{note:`Geeft langzaam formaldehyde vrij; risico op sensibilisatie.`},"imidazolidinyl urea":{note:`Formaldehyde-afgever; veelvoorkomende trigger voor contactallergie.`},"diazolidinyl urea":{note:`Formaldehyde-afgever; veelvoorkomende trigger voor contactallergie.`},"quaternium-15":{note:`Sterke formaldehyde-afgever; sinds 2022 verboden in EU-cosmetica.`},"2-bromo-2-nitropropane-1,3-diol":{note:`Formaldehyde-afgever; kan nitrosamines vormen met amines.`},methylisothiazolinone:{note:`Belangrijk contactallergeen; verboden in EU leave-on-producten.`},methylchloroisothiazolinone:{note:`Krachtige sensibilisator; in de EU alleen toegestaan in rinse-off-producten onder strenge limieten.`},triclosan:{note:`Zorgen over hormoonverstorende activiteit en antibioticaresistentie; beperkt in de EU.`},phenoxyethanol:{note:`Veelgebruikt; SCCS vindt het veilig bij ≤1%. Mild irritatiepotentieel.`},chlorphenesin:{note:`Conserveermiddel, incidenteel irriterend.`},"benzyl alcohol":{note:`Conserveermiddel en gedeclareerd geurallergeen.`},"sodium benzoate":{note:`Mild, goed verdragen conserveermiddel bij cosmetische doseringen.`},"potassium sorbate":{note:`Mild, goed verdragen conserveermiddel.`},"sodium lauryl sulfate":{note:`Effectieve reiniger; stript natuurlijke oliën en irriteert de gevoelige huid/hoofdhuid.`},"ammonium lauryl sulfate":{note:`Surfactant uit de SLS-klasse; vergelijkbaar irritatieprofiel.`},"sodium laureth sulfate":{note:`Milder dan SLS; sporen van 1,4-dioxane mogelijk door het productieproces.`},"cocamidopropyl betaine":{note:`Milde surfactant; allergieën veroorzaakt door onzuiverheden komen voor.`},"cocamide dea":{note:`IARC 2B (mogelijk kankerverwekkend); verboden in EU-cosmetica.`},"cocamide mea":{note:`Mogelijke vorming van nitrosamines met bepaalde conserveermiddelen.`},triethanolamine:{note:`pH-regelaar; zorgen over nitrosaminevorming in sommige formules.`},"benzophenone-3":{note:`Aanwijzingen voor hormoonverstorende activiteit; EU verlaagde toegestane concentratie in 2022. Ook toxisch voor koraalriffen.`},oxybenzone:{note:`Aanwijzingen voor hormoonverstorende activiteit; beperkt in de EU. Ook toxisch voor koraalriffen.`},"ethylhexyl methoxycinnamate":{note:`Oestrogene activiteit in onderzoeken; wordt geleidelijk afgebouwd.`},octocrylene:{note:`Kan afbreken tot benzofenon; meldingen van fotoallergie.`},homosalate:{note:`SCCS verlaagde de veilige concentratie vanwege vragen over hormoonverstoring.`},"butyl methoxydibenzoylmethane":{note:`Veelgebruikt UVA-filter; fotostabiliteit is het voornaamste probleem.`},"titanium dioxide":{note:`Veilig op de huid; vermijd inhaleerbare sprayvormen (nano).`},"zinc oxide":{note:`Mineraal UV-filter, goed verdragen.`},"polyethylene terephthalate":{note:`Vast synthetisch polymeer — bewust toegevoegd microplastic.`},polyethylene:{note:`Klassiek microbead-polymeer; EU-beperking wordt geleidelijk ingevoerd.`},polypropylene:{note:`Vast synthetisch polymeer — bewust toegevoegd microplastic.`},"polymethyl methacrylate":{note:`Acryl-microplastic dat gebruikt wordt voor textuur.`},"nylon-12":{note:`Polyamide microplasticpoeder.`},"nylon-6":{note:`Polyamide microplasticpoeder.`},"acrylates copolymer":{note:`Filmvormend polymeer; telt in vaste vorm als microplastic.`},"acrylates crosspolymer":{note:`Filmvormend polymeer; telt in vaste vorm als microplastic.`},cyclopentasiloxane:{note:`EU-beperkt in rinse-off-producten (vanwege milieupersistentie).`},cyclotetrasiloxane:{note:`Door de EU geclassificeerd als reprotoxisch en persistent; beperkt.`},dimethicone:{note:`Inerte filmvormer; veilig, al kan het zich opbouwen op het haar.`},amodimethicone:{note:`Verzorgende silicone, wordt goed verdragen.`},parfum:{note:`Niet-geopenbaard mengsel — de meest voorkomende bron van cosmetische allergieën.`},fragrance:{note:`Niet-geopenbaard mengsel — de meest voorkomende bron van cosmetische allergieën.`},limonene:{note:`Citrusgeurbestanddeel; verplicht aan te geven EU-allergeen bij oxidatie.`},linalool:{note:`Bloemig geurbestanddeel; verplicht aan te geven EU-allergeen bij oxidatie.`},citronellol:{note:`Verplicht aan te geven EU-geurallergeen.`},geraniol:{note:`Verplicht aan te geven EU-geurallergeen.`},eugenol:{note:`Verplicht aan te geven EU-geurallergeen.`},coumarin:{note:`Verplicht aan te geven EU-geurallergeen.`},"hexyl cinnamal":{note:`Verplicht aan te geven EU-geurallergeen.`},"benzyl salicylate":{note:`Verplicht aan te geven EU-geurallergeen.`},"alcohol denat":{note:`Uitdrogend voor de huid bij een hoge concentratie; prima mits laag op de lijst.`},"propylene glycol":{note:`Humectant/oplosmiddel; incidenteel gevoeligheid.`},"peg-":{note:`Geëthoxyleerde verbinding; sporen van 1,4-dioxaan mogelijk door de fabricage.`},"p-phenylenediamine":{note:`Sterk sensibiliserende stof — de klassieke haarverfallergie; EU-beperkt.`},resorcinol:{note:`Haarverfbestanddeel met bewijs voor schildklieractiviteit.`},hydroquinone:{note:`Huidverlichtend middel dat verboden is in EU-cosmetica.`},toluene:{note:`Neurotoxisch oplosmiddel; verboden in EU-cosmetica.`},"salicylic acid":{note:`Exfoliërend BHA; EU-concentratielimieten van toepassing, vermijden bij jonge kinderen.`},retinol:{note:`Effectieve anti-aging werkzame stof; EU beperkt concentratie, vermijden tijdens de zwangerschap.`},"aluminum chlorohydrate":{note:`Antitranspirantzout; SCCS beoordeelde het huidige gebruik als veilig (2020).`},talc:{note:`Veilig op de huid mits asbestvrij; vermijd inadembaar poeder nabij de longen.`},"mineral oil":{note:`Occlusief; zuiverheid is belangrijk (cosmetische kwaliteit is geraffineerd).`},"paraffinum liquidum":{note:`Minerale olie onder de INCI-naam; geraffineerde kwaliteiten zijn veilig.`},petrolatum:{note:`Occlusief; veilig mits goed geraffineerd (de EU vereist dit).`},lanolin:{note:`Afkomstig uit wol; effectief, maar een bekend contactallergeen.`},glycerin:{note:`Humectant die vocht bindt; behoort tot de veiligste ingrediënten in cosmetica.`},"hyaluronic acid":{note:`Vochtbindende werkzame stof, zeer goed verdragen.`},"sodium hyaluronate":{note:`Zoutvorm van hyaluronzuur; goed verdragen.`},panthenol:{note:`Provitamine B5 — daadwerkelijk verzorgend en een laag risico.`},niacinamide:{note:`Vitamine B3 — wetenschappelijk onderbouwd en goed verdragen.`},tocopherol:{note:`Vitamine E-antioxidant.`},ceramide:{note:`Huididentieke lipiden; ondersteuning van de huidbarrière.`}},r={ui:e,additives:t,inci:n};export{t as additives,r as default,n as inci,e as ui};